    const [status, setStatus] = useState<"idle" | "submitting" | "success" | "error">("idle");

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!SERVICE_ID || !TEMPLATE_ID || !PUBLIC_KEY) {
            alert("EmailJS keys are missing! Please check your configuration.");
            return;
        }

        setStatus("submitting");

        try {
            await emailjs.sendForm(
                SERVICE_ID,
                TEMPLATE_ID,
                formRef.current!,
                PUBLIC_KEY
            );
            setStatus("success");
            setFormData({ name: "", phone: "", email: "", message: "" });

            // Reset status after 3 seconds
            setTimeout(() => setStatus("idle"), 3000);

        } catch (error) {
            console.error("EmailJS Error:", error);
            setStatus("error");
            setTimeout(() => setStatus("idle"), 3000);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const inputClasses = "w-full px-4 py-3 bg-neutral-100 dark:bg-neutral-900/50 border border-neutral-200 dark:border-neutral-800 rounded-full focus:outline-none focus:ring-2 focus:ring-neutral-400 dark:focus:ring-neutral-500 transition-all placeholder:text-neutral-500 dark:placeholder:text-neutral-500 pl-10 text-neutral-900 dark:text-white [&:-webkit-autofill]:bg-neutral-100 dark:[&:-webkit-autofill]:bg-neutral-900 [&:-webkit-autofill]:shadow-[0_0_0_100px_#f5f5f5_inset] dark:[&:-webkit-autofill]:shadow-[0_0_0_100px_#171717_inset] [&:-webkit-autofill]:text-neutral-900 dark:[&:-webkit-autofill]:text-white";

    return (
        <section id="contact" className="py-32 flex justify-center w-full overflow-hidden relative">
            {/* Background Gradient */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] bg-neutral-200/20 dark:bg-neutral-800/20 rounded-full blur-[100px] -z-10" />

            <div className="max-w-4xl w-full px-6">

                <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    className="mb-12 text-center"
                >
                    <span className="inline-block px-3 py-1 text-xs font-medium tracking-wider uppercase bg-neutral-100 dark:bg-neutral-800 rounded-full text-neutral-600 dark:text-neutral-300 mb-4">
                        Contact
                    </span>
                    <h2 className="text-4xl md:text-5xl font-serif font-medium mb-6 text-neutral-900 dark:text-neutral-50">
                        Let's Work Together
                    </h2>
                    <p className="text-neutral-600 dark:text-neutral-400 max-w-xl mx-auto text-lg">
                        Have a project in mind or just want to say hello? Fill out the form below and I'll get back to you as soon as possible.
                    </p>
                </motion.div>

                <motion.form
                    ref={formRef}
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.2 }}
                    onSubmit={handleSubmit}
                    className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm"
                >
                    {/* Name */}
                    <div className="space-y-2">
                        <label htmlFor="name" className="text-sm font-medium text-neutral-700 dark:text-neutral-300 flex items-center gap-2 ml-1">
                            Name <span className="text-red-500">*</span>
                        </label>
                        <div className="relative group">
                            <input
                                type="text"
                                id="name"
                                name="name"
                                required
                                value={formData.name}
                                onChange={handleChange}
                                placeholder="batman"
                                className={inputClasses}
                            />
                            <User size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400 group-focus-within:text-neutral-900 dark:group-focus-within:text-white transition-colors" />
                        </div>
                    </div>

                    {/* Phone */}
                    <div className="space-y-2">
                        <label htmlFor="phone" className="text-sm font-medium text-neutral-700 dark:text-neutral-300 flex items-center gap-2 ml-1">
                            Phone <span className="text-red-500">*</span>
                        </label>
                        <div className="relative group">
                            <input
                                type="tel"
                                id="phone"
                                name="phone"
                                required
                                value={formData.phone}
                                onChange={handleChange}
                                placeholder="+91 9876543210"
                                className={inputClasses}
                            />
                            <Phone size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400 group-focus-within:text-neutral-900 dark:group-focus-within:text-white transition-colors" />
                        </div>
                    </div>

                    {/* Email */}
                    <div className="space-y-2 md:col-span-2">
                        <label htmlFor="email" className="text-sm font-medium text-neutral-700 dark:text-neutral-300 flex items-center gap-2 ml-1">
                            Email <span className="text-red-500">*</span>
                        </label>
                        <div className="relative group">
                            <input
                                type="email"
                                id="email"
                                name="email"
                                required
                                value={formData.email}
                                onChange={handleChange}
                                placeholder="wayne@gmail.com"
                                className={inputClasses}
                            />
                            <Mail size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400 group-focus-within:text-neutral-900 dark:group-focus-within:text-white transition-colors" />
                        </div>
                    </div>

                    {/* Message */}
                    <div className="space-y-2 md:col-span-2">
                        <label htmlFor="message" className="text-sm font-medium text-neutral-700 dark:text-neutral-300 flex items-center gap-2 ml-1">
                            Message <span className="text-red-500">*</span>
                        </label>
                        <div className="relative group">
                            <textarea
                                id="message"
                                name="message"
                                required
                                rows={5}
                                value={formData.message}
                                onChange={handleChange}
                                placeholder="Tell me about your project..."
                                className={inputClasses.replace("rounded-full", "rounded-2xl").replace("pl-10", "pl-10 pt-3 resize-none")}
                            />
                            <MessageSquare size={18} className="absolute left-3 top-4 text-neutral-400 group-focus-within:text-neutral-900 dark:group-focus-within:text-white transition-colors" />
                        </div>
                    </div>

                    {/* Submit Button */}
                    <div className="md:col-span-2 mt-2">
                        <button
                            type="submit"
                            disabled={status === "submitting" || status === "success"}
                            className="w-full inline-flex items-center justify-center gap-2 px-8 py-4 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-full font-medium hover:bg-neutral-800 dark:hover:bg-neutral-200 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5 disabled:opacity-70 disabled:cursor-not-allowed disabled:hover:translate-y-0 disabled:hover:shadow-lg"
                        >
                            {status === "idle" && (
                                <>
                                    <Send size={18} />
                                    Send Message
                                </>
                            )}
                            {status === "submitting" && (
                                <>
                                    <Loader2 size={18} className="animate-spin" />
                                    Sending...
                                </>
                            )}
                            {status === "success" && (
                                <>
                                    <CheckCircle2 size={18} className="text-green-600 dark:text-green-500" />
                                    Message Sent!
                                </>
                            )}
                            {status === "error" && (
                                <>
                                    <AlertCircle size={18} className="text-red-600 dark:text-red-500" />
                                    Failed to Send
                                </>
                            )}
                        </button>
                    </div>

                </motion.form>

                <motion.div
                    initial={{ opacity: 0 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.5 }}
                    className="mt-20 text-center text-neutral-400 text-sm flex flex-col items-center gap-1"
                >
                    <p>&copy; {new Date().getFullYear()} Om Singh. All rights reserved.</p>
                    <p className="text-xs text-neutral-400 dark:text-neutral-500 select-none">What happens if you click the cat 5 times...?</p>
                </motion.div>

            </div>
        </section>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Database, Search, ArrowRight, TableProperties, Binary, Play, RotateCcw } from "lucide-react";

type Stage = "idle" | "full_scan" | "btree_search";

export default function DatabaseIndexingDemo() {
    const [stage, setStage] = useState<Stage>("idle");
    const [scanIndex, setScanIndex] = useState(-1);
    const [treePath, setTreePath] = useState<string[]>([]);

    // Config
    const targetValue = 42;
    const tableData = Array.from({ length: 15 }, (_, i) => (i + 1) * 3); // 3, 6, 9... 45
    // Ensure 42 is in there at index 13

    const runFullScan = async () => {
        if (stage !== "idle") return;
        setStage("full_scan");
        setTreePath([]);

        for (let i = 0; i < tableData.length; i++) {
            setScanIndex(i);
            await new Promise(r => setTimeout(r, 150)); // Slow scan
            if (tableData[i] === targetValue) {
                break;
            }
        }
        await new Promise(r => setTimeout(r, 1000));
        setStage("idle");
        setScanIndex(-1);
    };

    const runBtreeSearch = async () => {
        if (stage !== "idle") return;
        setStage("btree_search");
        setScanIndex(-1);

        const path = [];
        // Root Node (midpoint roughly 24)
        path.push("root");
        setTreePath([...path]);
        await new Promise(r => setTimeout(r, 600));

        // Right Child (greater than 24, looks at 36)
        path.push("right");
        setTreePath([...path]);
        await new Promise(r => setTimeout(r, 600));

        // Right-Right Child (greater than 36, finds 42)
        path.push("right-right");
        setTreePath([...path]);

        await new Promise(r => setTimeout(r, 1500));
        setStage("idle");
        setTreePath([]);
    };

    const isRunning = stage !== "idle";

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <Binary size={20} className="text-neutral-500" />
                        Database Indexing (B-Tree)
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        Why are databases fast? If you don't use an Index, searching for a row requires a <strong className="text-red-500 font-normal">Full Table Scan</strong> (checking every single row).
                        An Index builds a balanced <strong>B-Tree</strong> structure in memory, allowing logarithmic <strong className="text-emerald-500 font-normal">O(log n)</strong> lookups.
                    </p>

                    <div className="bg-neutral-50 dark:bg-neutral-900/50 p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 mb-6 flex justify-between items-center text-[10px] uppercase font-bold tracking-widest text-neutral-500">
                        <span>Target Query</span>
                        <span className="text-indigo-500 font-mono text-sm">WHERE id = {targetValue}</span>
                    </div>
                </div>

                <div className="flex flex-col gap-3">
                    <button
                        onClick={runFullScan}
                        disabled={isRunning}
                        className="w-full bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900/40 text-red-700 dark:text-red-400 py-3 rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-red-100 dark:hover:bg-red-900/40 transition-all disabled:opacity-40 outline-none cursor-pointer text-xs"
                    >
                        <TableProperties size={16} /> Run Full Table Scan (O(n))
                    </button>
                    <button
                        onClick={runBtreeSearch}
                        disabled={isRunning}
                        className="w-full bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-900/40 text-emerald-700 dark:text-emerald-400 py-3 rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-emerald-100 dark:hover:bg-emerald-900/40 transition-all disabled:opacity-40 outline-none cursor-pointer text-xs"
                    >
                        <Binary size={16} /> Run B-Tree Index Search (O(log n))
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                {/* Table Data (Bottom) */}
                <div className="absolute bottom-6 left-6 right-6 p-4 rounded-xl border border-neutral-800 bg-neutral-800/50 flex flex-col gap-2">
                    <span className="text-[10px] uppercase font-bold text-neutral-500 flex items-center gap-2"><Database size={12} /> Physical Raw Data Pages</span>
                    <div className="flex w-full gap-1">
                        {tableData.map((val, i) => {
                            const isScanningThis = stage === 'full_scan' && scanIndex === i;
                            const isFound = val === targetValue && ((stage === 'full_scan' && scanIndex === i) || (stage === 'btree_search' && treePath.includes('right-right')));
                            const isPassedScan = stage === 'full_scan' && scanIndex > i;

                            return (
                                <div
                                    key={i}
                                    className={`flex-1 h-8 flex items-center justify-center text-[10px] md:text-xs font-bold rounded border transition-colors ${isFound ? 'bg-indigo-500 text-white border-indigo-400 shadow-[0_0_15px_rgba(99,102,241,0.5)]' :
                                            isScanningThis ? 'bg-red-500/20 border-red-500 text-red-400' :
                                                isPassedScan ? 'bg-neutral-900 border-neutral-700 text-neutral-600' :
                                                    'bg-neutral-800 border-neutral-700 text-neutral-400'
                                        }`}
                                >
                                    {val}
                                </div>
                            )
                        })}
                    </div>
                </div>

                {/* B-Tree Visualization (Top) */}
                <div className="flex-1 w-full flex flex-col items-center pt-8 relative z-10 transition-opacity duration-300" style={{ opacity: stage === 'full_scan' ? 0.3 : 1 }}>

                    <span className="absolute top-0 left-0 text-[10px] uppercase font-bold text-neutral-500 flex items-center gap-2 bg-neutral-800/50 px-2 py-1 rounded"><Search size={12} /> In-Memory Index (B-Tree)</span>

                    {/* Root Node */}
                    <div className="relative flex flex-col items-center mt-2">
                        <div className={`px-6 py-2 rounded border-2 z-20 transition-all shadow-lg ${treePath.includes('root') ? 'border-emerald-500 bg-emerald-500/20 text-emerald-300' : 'border-neutral-600 bg-neutral-800 text-neutral-400'}`}>
                            [ 24 ]
                        </div>

                        {/* Level 1 Nodes */}
                        <div className="flex w-64 justify-between mt-12 relative z-20">

                            {/* Left Child (<24) */}
                            <div className="px-4 py-1.5 rounded border-2 border-neutral-600 bg-neutral-800 text-neutral-400">
                                [ 12 ]
                            </div>

                            {/* Right Child (>24) */}
                            <div className={`px-4 py-1.5 rounded border-2 transition-all ${treePath.includes('right') ? 'border-emerald-500 bg-emerald-500/20 text-emerald-300' : 'border-neutral-600 bg-neutral-800 text-neutral-400'}`}>
                                [ 36 ]
                            </div>

                        </div>

                        {/* Level 2 Nodes (Leaf Pointers) */}
                        <div className="flex w-80 justify-between mt-12 relative z-20 text-[10px]">
                            <div className="px-2 py-1 rounded border border-neutral-700 bg-neutral-900 text-neutral-500">[ 3, 6, 9 ]</div>
                            <div className="px-2 py-1 rounded border border-neutral-700 bg-neutral-900 text-neutral-500">[ 15, 18, 21 ]</div>
                            <div className="px-2 py-1 rounded border border-neutral-700 bg-neutral-900 text-neutral-500">[ 27, 30, 33 ]</div>

                            <div className={`px-2 py-1 rounded border-2 transition-all ${treePath.includes('right-right') ? 'border-indigo-500 bg-indigo-500/20 text-indigo-300 shadow-[0_0_15px_rgba(99,102,241,0.5)]' : 'border-neutral-700 bg-neutral-900 text-neutral-500'}`}>
                                [ 39, 42, 45 ]
                            </div>
                        </div>

                        {/* Lines */}
                        <svg className="absolute inset-0 w-full h-full pointer-events-none -z-10 overflow-visible opacity-50">
                            {/* Root to L1 */}
                            <line x1="50%" y1="1.5rem" x2="25%" y2="4rem" stroke="#525252" strokeWidth="2" />
                            <line x1="50%" y1="1.5rem" x2="75%" y2="4rem" stroke={treePath.includes('right') ? '#10b981' : '#525252'} strokeWidth="2" />

                            {/* L1 Left to L2 */}
                            <line x1="25%" y1="5.5rem" x2="5%" y2="8.5rem" stroke="#525252" strokeWidth="2" />
                            <line x1="25%" y1="5.5rem" x2="35%" y2="8.5rem" stroke="#525252" strokeWidth="2" />

                            {/* L1 Right to L2 */}
                            <line x1="75%" y1="5.5rem" x2="65%" y2="8.5rem" stroke="#525252" strokeWidth="2" />
                            <line x1="75%" y1="5.5rem" x2="95%" y2="8.5rem" stroke={treePath.includes('right-right') ? '#10b981' : '#525252'} strokeWidth="2" />

                            {/* Pointer to DB */}
                            {treePath.includes('right-right') && (
                                <line x1="95%" y1="10rem" x2="95%" y2="15rem" stroke="#6366f1" strokeWidth="2" strokeDasharray="4 4" />
                            )}
                        </svg>
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Globe, Server, MonitorSmartphone, ArrowRight, Play, RotateCcw } from "lucide-react";

type Stage = "idle" | "browser_cache" | "isp_resolver" | "root_server" | "tld_server" | "auth_server" | "done";

export default function DnsResolutionDemo() {
    const [stage, setStage] = useState<Stage>("idle");
    const [logs, setLogs] = useState<{ id: string; msg: string; type: "info" | "success" | "warn" | "error" | "req" | "res" }[]>([]);

    const addLog = (msg: string, type: "info" | "success" | "warn" | "error" | "req" | "res") => {
        setLogs(prev => [{ id: crypto.randomUUID(), msg, type }, ...prev].slice(0, 6));
    };

    const runResolution = async () => {
        if (stage !== "idle" && stage !== "done") return;

        setStage("idle");
        setLogs([]);
        await new Promise(r => setTimeout(r, 400));

        // 1. Browser/OS Cache
        setStage("browser_cache");
        addLog("Browser: Checking local OS cache for 'google.com'...", "info");
        await new Promise(r => setTimeout(r, 1500));
        addLog("Browser Cache MISS. Not found locally.", "warn");
        await new Promise(r => setTimeout(r, 1000));

        // 2. ISP Resolver
        setStage("isp_resolver");
        addLog("OS: Asking ISP DNS Resolver (e.g. 8.8.8.8)...", "req");
        await new Promise(r => setTimeout(r, 1500));
        addLog("ISP Resolver: I don't know either. I'll find out for you.", "info");
        await new Promise(r => setTimeout(r, 1000));

        // 3. Root Server
        setStage("root_server");
        addLog("ISP: Asking Root DNS Server (.)", "req");
        await new Promise(r => setTimeout(r, 1500));
        addLog("Root: I don't know 'google.com', but ask the '.com' TLD Server at 192.x.x.x", "res");
        await new Promise(r => setTimeout(r, 1000));

        // 4. TLD Server
        setStage("tld_server");
        addLog("ISP: Asking '.com' TLD Server", "req");
        await new Promise(r => setTimeout(r, 1500));
        addLog("TLD: I don't know IP, but 'google.com' is registered to NameServers [ns1.google.com]", "res");
        await new Promise(r => setTimeout(r, 1000));

        // 5. Authoritative Server
        setStage("auth_server");
        addLog("ISP: Asking Authoritative Server (ns1.google.com)", "req");
        await new Promise(r => setTimeout(r, 1500));
        addLog("Auth: Yes! The A Record for google.com is 142.250.190.46", "success");
        await new Promise(r => setTimeout(r, 1000));

        // 6. Return Data
        setStage("done");
        addLog("ISP: Caching result and returning to Browser.", "info");
        addLog("Browser: Connecting to HTTP server at 142.250.190.46...", "success");
    };

    const isRunning = stage !== "idle" && stage !== "done";

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <Globe size={20} className="text-neutral-500" />
                        DNS Resolution Flow
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        What happens when you type <code>google.com</code> into your browser? Computers only understand IP addresses. The Domain Name System (DNS) is the phonebook of the internet, recursively querying servers across the globe to find an address.
                    </p>

                    <div className="bg-neutral-50 dark:bg-neutral-900/50 p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 mb-6">
                        <span className="text-neutral-500 text-[10px] uppercase font-bold tracking-widest block mb-2">Target Domain</span>
                        <div className="text-lg font-mono font-bold text-indigo-500 bg-white dark:bg-black p-2 rounded border border-neutral-200 dark:border-neutral-700 text-center">
                            google.com
                        </div>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={runResolution}
                        disabled={isRunning}
                        className="flex-1 bg-indigo-500 hover:bg-indigo-600 text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none disabled:opacity-50 cursor-pointer text-sm"
                    >
                        <Play size={16} /> Resolve Domain
                    </button>
                    <button
                        onClick={() => { setStage("idle"); setLogs([]); }}
                        disabled={isRunning}
                        className="px-6 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-xl font-medium border border-neutral-800 dark:border-neutral-200 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all outline-none cursor-pointer flex items-center justify-center disabled:opacity-50 text-sm"
                        title="Reset"
                    >
                        <RotateCcw size={16} />
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                <div className="flex-1 relative z-10 w-full mb-8">

                    <div className="flex justify-between items-center h-full px-4">

                        {/* Left Side: Client -> ISP */}
                        <div className="flex w-1/3 flex-col items-center justify-center gap-20 relative h-full">

                            {/* Client */}
                            <div className={`flex flex-col items-center gap-2 z-20 transition-all ${['browser_cache', 'done'].includes(stage) ? 'scale-110' : ''}`}>
                                <div className="w-16 h-16 rounded-xl border-2 border-indigo-500 bg-indigo-500/10 text-indigo-400 flex items-center justify-center shadow-[0_0_15px_rgba(99,102,241,0.2)]">
                                    <MonitorSmartphone size={32} />
                                </div>
                                <span className="text-[10px] uppercase font-bold text-indigo-400">Browser</span>
                            </div>

                            {/* ISP Resolver */}
                            <div className={`flex flex-col items-center gap-2 z-20 transition-all ${['isp_resolver', 'root_server', 'tld_server', 'auth_server'].includes(stage) ? 'scale-110' : ''}`}>
                                <div className="w-16 h-16 rounded-xl border-2 border-blue-500 bg-blue-500/10 text-blue-400 flex items-center justify-center shadow-[0_0_15px_rgba(59,130,246,0.2)]">
                                    <Server size={32} />
                                </div>
                                <span className="text-[10px] uppercase font-bold text-blue-400 text-center">ISP Resolver<br /><span className="text-[8px] font-normal opacity-70">(Recursive)</span></span>
