"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Lock, Unlock, Key, KeyRound, ShieldCheck, ArrowRight, Play, RotateCcw } from "lucide-react";

type Stage = "idle" | "encrypting" | "transit" | "decrypting" | "done";
type Mode = "symmetric" | "asymmetric";

export default function EncryptionDemo() {
    const [mode, setMode] = useState<Mode>("asymmetric");
    const [stage, setStage] = useState<Stage>("idle");

    const runSimulation = async () => {
        if (stage !== "idle" && stage !== "done") return;

        setStage("idle");
        await new Promise(r => setTimeout(r, 400));

        // 1. Encrypt
        setStage("encrypting");
        await new Promise(r => setTimeout(r, 1500));

        // 2. Transit over network
        setStage("transit");
        await new Promise(r => setTimeout(r, 2000));

        // 3. Decrypt
        setStage("decrypting");
        await new Promise(r => setTimeout(r, 1500));

        // 4. Done
        setStage("done");
    };

    const isRunning = stage !== "idle" && stage !== "done";

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <Lock size={20} className="text-neutral-500" />
                        Symmetric vs Asymmetric
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        <strong>Symmetric</strong> encryption (like AES) uses the <em>same</em> key to lock and unlock data. It's extremely fast but hard to share the key safely.
                        <br /><br />
                        <strong>Asymmetric</strong> encryption (like RSA) uses a mathematically linked Public/Private key pair. Anyone can lock data with the Public Key, but <em>only</em> the Private Key can unlock it.
                    </p>

                    <div className="flex flex-col gap-2 mb-6">
                        {(["symmetric", "asymmetric"] as Mode[]).map(m => (
                            <button
                                key={m}
                                onClick={() => { setMode(m); setStage("idle"); }}
                                disabled={isRunning}
                                className={`px-4 py-3 rounded-xl text-left text-sm font-bold transition-colors border capitalize ${mode === m
                                        ? m === 'symmetric' ? 'bg-orange-500 text-white border-orange-600' : 'bg-indigo-500 text-white border-indigo-600'
                                        : 'bg-neutral-50 dark:bg-neutral-900 text-neutral-500 border-neutral-200 dark:border-neutral-800 hover:bg-neutral-100 dark:hover:bg-neutral-800'
                                    }`}
                            >
                                {m} Encryption
                            </button>
                        ))}
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={runSimulation}
                        disabled={isRunning}
                        className={`flex-1 ${mode === 'symmetric' ? 'bg-orange-500 hover:bg-orange-600' : 'bg-indigo-500 hover:bg-indigo-600'} text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none disabled:opacity-50 cursor-pointer text-sm`}
                    >
                        <Play size={16} /> Send Secure Message
                    </button>
                    <button
                        onClick={() => setStage("idle")}
                        disabled={isRunning}
                        className="px-6 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-xl font-medium border border-neutral-800 dark:border-neutral-200 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all outline-none cursor-pointer flex items-center justify-center disabled:opacity-50 text-sm"
                        title="Reset"
                    >
                        <RotateCcw size={16} />
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col items-center justify-center relative overflow-hidden font-mono min-h-[450px]">

                {/* Keys Display Section */}
                <div className="absolute top-6 left-6 right-6 flex justify-between px-8">
                    {/* Client Profile */}
                    <div className="flex flex-col items-center gap-2">
                        <span className="text-[10px] uppercase font-bold text-neutral-500">Sender (Alice)</span>
                        {mode === 'symmetric' ? (
                            <div className="px-3 py-1.5 rounded-full border border-orange-500/50 bg-orange-500/10 text-orange-400 text-xs flex items-center gap-1">
                                <Key size={12} /> Key "XYZ"
                            </div>
                        ) : (
                            <div className="px-3 py-1.5 rounded-full border border-emerald-500/50 bg-emerald-500/10 text-emerald-400 text-xs flex items-center gap-1 shadow-[0_0_10px_rgba(52,211,153,0.2)]">
                                <KeyRound size={12} /> Bob's Public Key
                            </div>
                        )}
                    </div>

                    {/* Server Profile */}
                    <div className="flex flex-col items-center gap-2">
                        <span className="text-[10px] uppercase font-bold text-neutral-500">Receiver (Bob)</span>
                        {mode === 'symmetric' ? (
                            <div className="px-3 py-1.5 rounded-full border border-orange-500/50 bg-orange-500/10 text-orange-400 text-xs flex items-center gap-1">
                                <Key size={12} /> Key "XYZ"
                            </div>
                        ) : (
                            <div className="flex gap-2">
                                <div className="px-3 py-1.5 rounded-full border border-emerald-500/50 bg-emerald-500/10 text-emerald-400 text-xs flex items-center gap-1">
                                    <KeyRound size={12} /> Public Key
                                </div>
                                <div className="px-3 py-1.5 rounded-full border border-red-500/50 bg-red-500/10 text-red-400 text-xs flex items-center gap-1 shadow-[0_0_10px_rgba(239,68,68,0.2)]">
                                    <Key size={12} /> Private Key
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* The Interactive Payload */}
                <div className="w-full h-40 relative mt-20 flex px-12 items-center">

                    {/* Safe Zone (Client) */}
                    <div className="w-1/4 h-full border-r-2 border-dashed border-neutral-700 relative flex items-center" />
                    {/* Danger Zone (Internet) */}
                    <div className="w-2/4 h-full relative" />
                    {/* Safe Zone (Server) */}
                    <div className="w-1/4 h-full border-l-2 border-dashed border-neutral-700 relative flex items-center justify-end" />

                    {/* The Message Object */}
                    <AnimatePresence>
                        <motion.div
                            className={`absolute top-1/2 -translate-y-1/2 flex flex-col items-center justify-center w-32 h-24 rounded-xl border-2 transition-colors z-20 shadow-2xl ${['encrypting', 'decrypting'].includes(stage) ? 'border-yellow-500 bg-yellow-500/20 text-yellow-300 backdrop-blur-md' :
                                    ['transit'].includes(stage) ? 'border-red-500 bg-neutral-900 text-red-400 backdrop-blur-md' :
                                        'border-emerald-500 bg-emerald-500/20 text-emerald-300 backdrop-blur-md'
                                }`}
                            initial={{ left: "10%" }}
                            animate={{
                                left: stage === 'idle' ? "10%" :
                                    stage === 'encrypting' ? "10%" :
                                        stage === 'transit' ? "50%" :
                                            stage === 'decrypting' ? "85%" : "85%",
                                rotate: ['transit'].includes(stage) ? [0, -5, 5, -5, 5, 0] : 0
                            }}
                            transition={{ duration: stage === 'transit' ? 2 : 0.5, ease: "easeInOut" }}
                        >
                            {/* Content of Message */}
                            {stage === 'idle' && (
                                <>
                                    <Unlock size={24} className="mb-2" />
                                    <span className="text-[10px] font-bold">"HELLO BOB"</span>
                                </>
                            )}
                            {stage === 'encrypting' && (
                                <>
                                    <Lock size={24} className="mb-2 animate-pulse" />
                                    <span className="text-[10px] font-bold text-center">LOCKING WITH<br />{mode === 'symmetric' ? 'KEY "XYZ"' : 'PUB KEY'}</span>
                                </>
                            )}
                            {stage === 'transit' && (
                                <>
                                    <Lock size={24} className="mb-2" />
                                    <span className="text-[10px] font-bold opacity-50 break-all px-2 text-center overflow-hidden">
                                        8F2a9B1c...
                                    </span>
                                </>
                            )}
                            {stage === 'decrypting' && (
                                <>
                                    <Unlock size={24} className="mb-2 animate-pulse" />
                                    <span className="text-[10px] font-bold text-center">UNLOCKING WITH<br />{mode === 'symmetric' ? 'KEY "XYZ"' : 'PRIV KEY'}</span>
                                </>
                            )}
                            {stage === 'done' && (
                                <>
                                    <ShieldCheck size={24} className="mb-2" />
                                    <span className="text-[10px] font-bold">"HELLO BOB"</span>
                                </>
                            )}
                        </motion.div>
                    </AnimatePresence>
                </div>

                {/* Explanation Text */}
                <div className="absolute bottom-8 text-center px-12 w-full">
                    <div className="h-16 flex items-center justify-center text-xs text-neutral-400">
                        {stage === 'idle' && "1. Plaintext data ready to be sent securely."}
                        {stage === 'encrypting' && (mode === 'symmetric' ? "2. Encrypting with the shared secret key." : "2. Encrypting with Bob's Public Key (anyone can do this).")}
                        {stage === 'transit' && "3. Secure transit over the public internet. Hackers only see gibberish."}
                        {stage === 'decrypting' && (mode === 'symmetric' ? "4. Unlocking with the SAME shared secret." : "4. Unlocking with Bob's Private Key (ONLY Bob can do this).")}
                        {stage === 'done' && "5. Decryption successful. Message secured."}
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { DollarSign, Database, RotateCcw, PlusCircle, MinusCircle } from "lucide-react";

interface BankEvent {
    id: string;
    type: "DEPOSIT" | "WITHDRAWAL";
    amount: number;
    timestamp: Date;
}

export default function EventSourcingDemo() {
    // We strictly store EVENTS, not the "balance"
    const [eventStore, setEventStore] = useState<BankEvent[]>([]);

    const appendEvent = (type: "DEPOSIT" | "WITHDRAWAL", amount: number) => {
        setEventStore(prev => [
            { id: crypto.randomUUID().slice(0, 8), type, amount, timestamp: new Date() },
            ...prev
        ]);
    };

    const undoLastEvent = () => {
        if (eventStore.length === 0) return;
        setEventStore(prev => prev.slice(1));
    };

    // CQRS Projection: We derive the state purely by folding the event log
    const calculateBalance = (events: BankEvent[]) => {
        return events.reduce((acc, ev) => {
            return ev.type === "DEPOSIT" ? acc + ev.amount : acc - ev.amount;
        }, 0);
    };

    const currentBalance = calculateBalance(eventStore);

    return (
        <div className="w-full bg-neutral-900 border border-neutral-800 shadow-2xl rounded-[2rem] overflow-hidden flex flex-col md:flex-row min-h-[500px]">

            {/* WRITE SIDE (Command) */}
            <div className="w-full md:w-1/2 p-8 border-r border-neutral-800 bg-neutral-950 flex flex-col">
                <div className="mb-8 pb-4 border-b border-neutral-800">
                    <h3 className="text-lg font-medium text-white flex items-center gap-2">
                        <Database size={20} className="text-emerald-500" />
                        Command Side (Write)
                    </h3>
                    <p className="text-xs text-neutral-500 mt-1">Appends immutable facts to Event Store</p>
                </div>

                <div className="flex gap-4 mb-8">
                    <button
                        onClick={() => appendEvent("DEPOSIT", 100)}
                        className="flex-1 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 rounded-xl py-4 flex flex-col items-center justify-center gap-2 transition-colors group cursor-pointer"
                    >
                        <PlusCircle size={24} className="group-hover:scale-110 transition-transform" />
                        <span className="font-bold tracking-wide">Deposit $100</span>
                    </button>
                    <button
                        onClick={() => appendEvent("WITHDRAWAL", 50)}
                        className="flex-1 bg-rose-500/10 hover:bg-rose-500/20 text-rose-400 border border-rose-500/30 rounded-xl py-4 flex flex-col items-center justify-center gap-2 transition-colors group disabled:cursor-not-allowed cursor-pointer"
                        disabled={currentBalance < 50}
                    >
                        <MinusCircle size={24} className="group-hover:scale-110 transition-transform" />
                        <span className="font-bold tracking-wide">Withdraw $50</span>
                    </button>
                </div>

                <div className="flex flex-col flex-1 bg-black p-4 rounded-xl border border-neutral-800 relative z-0">
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-xs font-mono text-neutral-500 uppercase">Event Store Log</span>
                        <button
                            onClick={undoLastEvent}
                            disabled={eventStore.length === 0}
                            className="bg-neutral-800 hover:bg-neutral-700 text-neutral-300 px-3 py-1 rounded text-xs flex items-center gap-1 transition-colors disabled:opacity-30 disabled:cursor-not-allowed z-10 cursor-pointer"
                        >
                            <RotateCcw size={12} /> Rewind 1 Step
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto space-y-2 pr-2 scrollbar-thin scrollbar-thumb-neutral-800">
                        <AnimatePresence>
                            {eventStore.length === 0 && (
                                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-neutral-600 text-sm italic text-center mt-10">
                                    No events recorded. Book is empty.
                                </motion.div>
                            )}
                            {eventStore.map((ev, i) => (
                                <motion.div
                                    key={ev.id}
                                    initial={{ opacity: 0, x: -20, height: 0 }}
                                    animate={{ opacity: 1, x: 0, height: "auto" }}
                                    exit={{ opacity: 0, x: 20, height: 0 }}
                                    className="bg-neutral-900 border border-neutral-800 p-3 rounded-lg font-mono text-xs flex justify-between items-center"
                                >
                                    <div className="flex flex-col">
                                        <span className="text-neutral-500">Event_{ev.id}</span>
                                        <span className={ev.type === "DEPOSIT" ? "text-emerald-400" : "text-rose-400"}>
                                            {ev.type}
                                        </span>
                                    </div>
                                    <span className="text-white text-sm font-bold">${ev.amount}</span>
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>
                </div>
            </div>

            {/* READ SIDE (Query) */}
            <div className="w-full md:w-1/2 p-8 flex flex-col relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 blur-[100px] pointer-events-none rounded-full" />

                <div className="mb-8 pb-4 border-b border-neutral-800 z-10">
                    <h3 className="text-lg font-medium text-white flex items-center gap-2">
                        <DollarSign size={20} className="text-indigo-400" />
                        Query Side (Read)
                    </h3>
                    <p className="text-xs text-neutral-500 mt-1">Projects state purely by deriving from logs</p>
                </div>

                <div className="flex-1 flex flex-col items-center justify-center z-10">
                    <div className="bg-neutral-950 border border-neutral-800 p-8 rounded-3xl shadow-2xl flex flex-col items-center w-full max-w-sm">
                        <span className="text-neutral-500 font-medium uppercase tracking-widest text-sm mb-4">Total Balance</span>

                        <div className="text-6xl font-serif font-medium text-white tracking-widest flex items-start gap-1">
                            <span className="text-2xl mt-2 text-neutral-400">$</span>
                            <motion.span
                                key={currentBalance}
                                initial={{ scale: 1.2, color: "#10b981" }}
                                animate={{ scale: 1, color: "#ffffff" }}
                                transition={{ type: "spring", stiffness: 300, damping: 20 }}
                            >
                                {currentBalance}
                            </motion.span>
                        </div>

                        <div className="w-full h-px bg-neutral-800 my-8" />

                        <div className="w-full space-y-3">
                            <div className="flex justify-between text-xs text-neutral-400">
                                <span>Total Transactions</span>
                                <span className="font-mono text-white">{eventStore.length}</span>
                            </div>
                            <div className="flex justify-between text-xs text-neutral-400">
                                <span>Derived State</span>
                                <span className={eventStore.length === 0 ? "text-yellow-500" : "text-emerald-500"}>
                                    {eventStore.length === 0 ? "Empty" : "Synced"}
                                </span>
                            </div>
                        </div>
                    </div>
                    <p className="text-xs text-neutral-500 mt-6 text-center max-w-[200px]">
                        Even if this database crashes, it can recreate this exact balance by re-reading the event logs!
                    </p>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Map, MapPin, Grid3X3, ArrowRight, MousePointerClick, Zap } from "lucide-react";

export default function GeohashingDemo() {
    const [zoomLevel, setZoomLevel] = useState(0); // 0 to 4

    // Abstract grid definitions for visual purposes
    const grids = [
        { level: 0, code: "", size: 1, cols: 2, rows: 2, prefix: "" }, // Base World (4 quadrants for simplicity, real geohash uses base32)
        { level: 1, code: "g", size: 0.5, cols: 4, rows: 4, prefix: "g" },
        { level: 2, code: "gc", size: 0.25, cols: 8, rows: 8, prefix: "gc" },
        { level: 3, code: "gcp", size: 0.125, cols: 16, rows: 16, prefix: "gcp" },
        { level: 4, code: "gcpv", size: 0.0625, cols: 32, rows: 32, prefix: "gcpv" },
    ];

    const currentGrid = grids[zoomLevel];

