"use client";

import React, { useState, useEffect } from "react";
import { GitHubCalendar } from "react-github-calendar";
import { motion } from "framer-motion";
import { portfolioData } from "@/data/portfolio";

export default function GithubGraph() {
    const [isDark, setIsDark] = useState(false);
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
        // Check initial theme
        if (typeof document !== "undefined") {
            setIsDark(document.documentElement.classList.contains("dark"));

            // Observe dark mode changes
            const observer = new MutationObserver((mutations) => {
                mutations.forEach((mutation) => {
                    if (mutation.attributeName === "class") {
                        setIsDark(document.documentElement.classList.contains("dark"));
                    }
                });
            });

            observer.observe(document.documentElement, {
                attributes: true,
            });

            return () => observer.disconnect();
        }
    }, []);

    if (!mounted) {
        return (
            <section className="py-10 max-w-4xl mx-auto px-5 w-full">
                <div className="h-[150px] w-full animate-pulse bg-neutral-100 dark:bg-neutral-900 rounded-2xl" />
            </section>
        );
    }

    const githubUrl = portfolioData.socials.github;
    const username = githubUrl.split("/").pop() || "Singh-OmDev";

    return (
        <section className="py-24 md:py-32 flex justify-center bg-white dark:bg-black overflow-hidden w-full">
            <div className="max-w-6xl w-full px-6 grid grid-cols-1 md:grid-cols-12 gap-12 md:gap-20 items-center">
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.8, ease: "easeOut" }}
                    className="md:col-span-12 max-w-4xl mx-auto text-center w-full"
                >
                    <div className="flex items-center justify-center gap-4 mb-12">
                        <div className="h-px w-12 bg-neutral-900 dark:bg-white" />
                        <span className="text-sm font-medium tracking-widest uppercase text-neutral-900 dark:text-white">
                            GitHub Activity
                        </span>
                        <div className="h-px w-12 bg-neutral-900 dark:bg-white" />
                    </div>

                    <div className="flex justify-center w-full overflow-x-auto pb-4 scrollbar-hide">
                        <div className="min-w-max">
                            <GitHubCalendar
                                username={username}
                                colorScheme={isDark ? "dark" : "light"}
                                blockSize={12}
                                blockMargin={4}
                                fontSize={14}
                            />
                        </div>
                    </div>
                </motion.div>
            </div>
        </section>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Network, Server, Play, RotateCcw, Activity } from "lucide-react";

type NodeState = "clean" | "infected";
type MessageTick = { id: string; from: number; to: number };

export default function GossipProtocolDemo() {
    const [nodes, setNodes] = useState<Record<number, NodeState>>({
        1: "clean", 2: "clean", 3: "clean", 4: "clean", 5: "clean",
        6: "clean", 7: "clean", 8: "clean", 9: "clean", 10: "clean"
    });

    const [messages, setMessages] = useState<MessageTick[]>([]);
    const [isRunning, setIsRunning] = useState(false);
    const [tickCount, setTickCount] = useState(0);
    const intervalRef = useRef<NodeJS.Timeout | null>(null);

    // Positions for 10 nodes (roughly a circle)
    const positions = Array.from({ length: 10 }).map((_, i) => {
        const angle = (i / 10) * Math.PI * 2 - Math.PI / 2;
        const radius = 40; // percentage
        return {
            left: `${50 + radius * Math.cos(angle)}%`,
            top: `${50 + radius * Math.sin(angle)}%`,
        };
    });

    const triggerInfection = (startNode: number) => {
        if (isRunning) return;
        setNodes(prev => ({ ...prev, [startNode]: "infected" }));
        setIsRunning(true);
        setTickCount(0);
        setMessages([]);
    };

    const resetSimulation = () => {
        if (intervalRef.current) clearInterval(intervalRef.current);
        setNodes(Object.fromEntries(Array.from({ length: 10 }).map((_, i) => [i + 1, "clean"])) as any);
        setMessages([]);
        setIsRunning(false);
        setTickCount(0);
    };

    useEffect(() => {
        if (!isRunning) return;

        intervalRef.current = setInterval(() => {
            setTickCount(prev => prev + 1);

            setNodes(currentNodes => {
                const infectedNodes = Object.keys(currentNodes).map(Number).filter(n => currentNodes[n] === "infected");

                if (infectedNodes.length === 10) {
                    setIsRunning(false);
                    return currentNodes; // All infected, halt
                }

                const newMessages: MessageTick[] = [];
                const nextNodes = { ...currentNodes };

                // Each infected node picks 1 random peer to gossip to
                infectedNodes.forEach(fromNode => {
                    let toNode: number;
                    do {
                        toNode = Math.floor(Math.random() * 10) + 1;
                    } while (toNode === fromNode);

                    // Record the message animation
                    newMessages.push({ id: crypto.randomUUID(), from: fromNode, to: toNode });

                    // Infect the target
                    nextNodes[toNode] = "infected";
                });

                setMessages(newMessages); // Just keep the current tick's messages for animation
                return nextNodes;
            });

        }, 1200); // 1.2s per tick

        return () => {
            if (intervalRef.current) clearInterval(intervalRef.current);
        };
    }, [isRunning]);

    const infectedCount = Object.values(nodes).filter(v => v === "infected").length;
    const isComplete = infectedCount === 10;

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <Network size={20} className="text-neutral-500" />
                        Gossip Protocol
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        Masterless distributed databases (like Apache Cassandra) don't have a central leader. Instead, nodes randomly select a peer every second to "gossip" with, trading state updates. Like a viral infection, data synchronizes exponentially fast across the entire cluster.
                    </p>

                    <div className="bg-neutral-50 dark:bg-neutral-900/50 p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 mb-6 font-mono text-[10px] flex justify-between items-center">
                        <div className="flex flex-col gap-1">
                            <span className="text-neutral-500">Infected Nodes</span>
                            <span className="text-lg font-bold text-indigo-500">{infectedCount} / 10</span>
                        </div>
                        <div className="flex flex-col gap-1 text-right">
                            <span className="text-neutral-500">Gossip Rounds</span>
                            <span className="text-lg font-bold text-neutral-800 dark:text-neutral-200">{tickCount}</span>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={() => triggerInfection(1)}
                        disabled={isRunning || infectedCount > 0}
                        className="flex-1 bg-indigo-500 hover:bg-indigo-600 text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none disabled:opacity-50 cursor-pointer text-sm"
                    >
                        <Play size={16} /> Start Gossip
                    </button>
                    <button
                        onClick={resetSimulation}
                        className="px-6 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-xl font-medium border border-neutral-800 dark:border-neutral-200 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all outline-none cursor-pointer flex items-center justify-center"
                        title="Reset"
                    >
                        <RotateCcw size={16} />
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                {isComplete && (
                    <div className="absolute inset-0 flex items-center justify-center z-30 bg-black/50 backdrop-blur-sm">
                        <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-indigo-500/20 border border-indigo-500/50 px-6 py-4 rounded-2xl flex flex-col items-center gap-2 shadow-[0_0_30px_rgba(99,102,241,0.3)]">
                            <Activity size={32} className="text-indigo-400 mb-2" />
                            <span className="text-sm font-bold text-white tracking-widest uppercase">Eventually Consistent</span>
                            <span className="text-[10px] text-indigo-300">Cluster synchronized in {tickCount} rounds.</span>
                        </motion.div>
                    </div>
                )}

                <div className="flex-1 relative z-10 w-full h-full my-8">

                    {/* Draw Nodes */}
                    {Array.from({ length: 10 }).map((_, i) => {
                        const id = i + 1;
                        const isInfected = nodes[id] === "infected";
                        const pos = positions[i];

                        return (
                            <div key={id} className="absolute flex flex-col items-center justify-center -translate-x-1/2 -translate-y-1/2 transition-all duration-300" style={pos}>

                                <div className={`w-12 h-12 rounded-xl border-2 flex items-center justify-center relative z-20 transition-all duration-500 ${isInfected
                                        ? 'bg-indigo-500 border-indigo-300 shadow-[0_0_20px_rgba(99,102,241,0.5)] scale-110 text-white'
                                        : 'bg-neutral-800 border-neutral-600 text-neutral-500'
                                    }`}>
                                    <Server size={20} />

                                    {/* Pulse effect if freshly infected or gossiping */}
                                    <AnimatePresence>
                                        {isInfected && isRunning && (
                                            <motion.div
                                                initial={{ scale: 1, opacity: 0.8 }}
                                                animate={{ scale: 2, opacity: 0 }}
                                                exit={{ opacity: 0 }}
                                                transition={{ duration: 1.2, repeat: Infinity }}
                                                className="absolute inset-0 rounded-xl border-2 border-indigo-400 pointer-events-none"
                                            />
                                        )}
                                    </AnimatePresence>
                                </div>
                                <span className={`text-[9px] font-bold mt-2 tracking-widest uppercase ${isInfected ? 'text-indigo-300' : 'text-neutral-500'}`}>Node {id}</span>
                            </div>
                        )
                    })}

                    {/* Draw Flying Particles (Messages) */}
                    <AnimatePresence>
                        {messages.map((msg, idx) => {
                            const fromPos = positions[msg.from - 1];
                            const toPos = positions[msg.to - 1];

                            return (
                                <motion.div
                                    key={`${msg.id}-${idx}`}
                                    initial={{
                                        left: fromPos.left,
                                        top: fromPos.top,
                                        opacity: 0,
                                        scale: 0.5
                                    }}
                                    animate={{
                                        left: toPos.left,
                                        top: toPos.top,
                                        opacity: 1,
                                        scale: 1
                                    }}
                                    exit={{ opacity: 0, scale: 0 }}
                                    transition={{ duration: 0.8, ease: "easeInOut" }}
                                    className="absolute w-3 h-3 bg-indigo-400 rounded-full shadow-[0_0_15px_#818cf8] z-30 -translate-x-1/2 -translate-y-1/2 pointer-events-none"
                                />
                            );
                        })}
                    </AnimatePresence>

                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Network, FileJson2, ArrowRightCircle, Database, Server, RefreshCcw } from "lucide-react";

export default function GraphqlDemo() {
    const [isFetching, setIsFetching] = useState(false);

    // REST State
    const [restProgress, setRestProgress] = useState(0); // 0, 1, 2, 3 (Done)
    const [restData, setRestData] = useState<any>(null);

    // GQL State
    const [gqlProgress, setGqlProgress] = useState(0); // 0 or 1 (Done)
    const [gqlData, setGqlData] = useState<any>(null);

    const startRace = () => {
        if (isFetching) return;

        setIsFetching(true);
        setRestProgress(0);
        setRestData(null);
        setGqlProgress(0);
        setGqlData(null);

        // --- REST Waterfall Simulation ---
        // Step 1: /api/user
        setTimeout(() => {
            setRestProgress(1);

            // Step 2: /api/posts
            setTimeout(() => {
                setRestProgress(2);

                // Step 3: /api/friends
                setTimeout(() => {
                    setRestProgress(3);
                    setRestData({ name: "Om", posts: ["Post 1", "Post 2"], friends: 42 });
                }, 500); // TTT = 1500ms
            }, 500);
        }, 500);

        // --- GraphQL Single Query Simulation ---
        // 1 Trip, but slightly longer processing time on backend
        setTimeout(() => {
            setGqlProgress(1);
            setGqlData({ name: "Om", posts: ["Post 1", "Post 2"], friends: 42 });
        }, 800); // TTT = 800ms
    };

    return (
        <div className="w-full bg-neutral-50 dark:bg-black p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col gap-8 min-h-[500px]">

            <div className="flex justify-between items-center">
                <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2">
                    <ArrowRightCircle size={20} className="text-neutral-500" />
                    Data Fetching Race
                </h3>
                <button
                    onClick={startRace}
                    disabled={isFetching && restProgress < 3}
                    className="px-6 py-2.5 bg-indigo-500 hover:bg-indigo-600 text-white rounded-full text-sm font-medium transition-colors flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer"
                >
                    <RefreshCcw size={16} className={isFetching && restProgress < 3 ? "animate-spin" : ""} />
                    {isFetching && restProgress < 3 ? "Fetching..." : "Run Benchmark"}
                </button>
            </div>

            <div className="flex flex-col md:flex-row gap-6 flex-1">

                {/* REST Lane */}
                <div className="flex-1 border border-neutral-200 dark:border-neutral-800 rounded-2xl bg-white dark:bg-neutral-900/50 p-6 flex flex-col overflow-hidden relative">
                    <div className="flex justify-between items-center mb-6">
                        <span className="font-bold text-neutral-800 dark:text-neutral-200">REST API</span>
                        <span className="text-xs bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400 px-2 py-1 rounded font-mono">Multiple Round Trips</span>
                    </div>

                    <div className="flex-1 flex flex-col justify-center gap-4 border-l-2 border-neutral-200 dark:border-neutral-800 ml-4 pl-6 py-4">

                        {/* Request 1 */}
                        <div className="relative">
                            <div className={`absolute -left-[35px] top-1/2 -translate-y-1/2 w-4 h-4 rounded-full border-2 border-white dark:border-neutral-900 z-10 transition-colors duration-300 ${restProgress >= 1 ? 'bg-green-500' : 'bg-neutral-300 dark:bg-neutral-700'}`} />
                            <div className={`p-3 rounded-xl border transition-all duration-300 ${restProgress === 0 && isFetching ? 'border-blue-500 bg-blue-50/50 dark:bg-blue-900/10' : 'border-neutral-200 dark:border-neutral-800 bg-neutral-50 dark:bg-neutral-950'} ${restProgress >= 1 ? 'opacity-50' : ''}`}>
                                <div className="text-xs font-mono text-neutral-500 mb-1">GET /api/users/me</div>
                                <div className="text-xs text-neutral-800 dark:text-neutral-300">{restProgress >= 1 ? 'Returns { name: "Om" }' : 'Waiting...'}</div>
                            </div>
                        </div>

                        {/* Request 2 (Waterfall) */}
                        <div className="relative">
                            <div className={`absolute -left-[35px] top-1/2 -translate-y-1/2 w-4 h-4 rounded-full border-2 border-white dark:border-neutral-900 z-10 transition-colors duration-300 ${restProgress >= 2 ? 'bg-green-500' : 'bg-neutral-300 dark:bg-neutral-700'}`} />
                            <div className={`p-3 rounded-xl border transition-all duration-300 ${restProgress === 1 ? 'border-blue-500 bg-blue-50/50 dark:bg-blue-900/10' : 'border-neutral-200 dark:border-neutral-800 bg-neutral-50 dark:bg-neutral-950'} ${restProgress >= 2 ? 'opacity-50' : ''}`}>
                                <div className="text-xs font-mono text-neutral-500 mb-1">GET /api/users/me/posts</div>
                                <div className="text-xs text-neutral-800 dark:text-neutral-300">{restProgress >= 2 ? 'Returns { posts: [...] }' : 'Blocked by Req 1'}</div>
                            </div>
                        </div>

                        {/* Request 3 (Waterfall) */}
                        <div className="relative">
                            <div className={`absolute -left-[35px] top-1/2 -translate-y-1/2 w-4 h-4 rounded-full border-2 border-white dark:border-neutral-900 z-10 transition-colors duration-300 ${restProgress >= 3 ? 'bg-green-500' : 'bg-neutral-300 dark:bg-neutral-700'}`} />
                            <div className={`p-3 rounded-xl border transition-all duration-300 ${restProgress === 2 ? 'border-blue-500 bg-blue-50/50 dark:bg-blue-900/10' : 'border-neutral-200 dark:border-neutral-800 bg-neutral-50 dark:bg-neutral-950'} ${restProgress >= 3 ? 'opacity-50' : ''}`}>
                                <div className="text-xs font-mono text-neutral-500 mb-1">GET /api/users/me/friends</div>
                                <div className="text-xs text-neutral-800 dark:text-neutral-300">{restProgress >= 3 ? 'Returns { count: 42 }' : 'Blocked by Req 2'}</div>
                            </div>
                        </div>

                    </div>
                </div>

                {/* GraphQL Lane */}
                <div className="flex-1 border border-neutral-200 dark:border-neutral-800 rounded-2xl bg-white dark:bg-neutral-900/50 p-6 flex flex-col overflow-hidden relative">
                    <div className="flex justify-between items-center mb-6">
                        <span className="font-bold text-[#E10098]">GraphQL</span>
                        <span className="text-xs bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 px-2 py-1 rounded font-mono">Single Round Trip</span>
                    </div>

                    <div className="flex-1 flex flex-col justify-center items-center h-full">
                        <div className={`w-full p-4 rounded-xl border transition-all duration-500 ${isFetching && gqlProgress === 0 ? 'border-blue-500 bg-blue-50/50 dark:bg-blue-900/10 scale-105 shadow-xl' : 'border-neutral-200 dark:border-neutral-800 bg-neutral-50 dark:bg-neutral-950 scale-100'}`}>
                            <div className="text-xs font-mono text-[#E10098] font-bold mb-3 flex items-center justify-between">
                                POST /graphql
                                {isFetching && gqlProgress === 0 && <span className="animate-pulse w-2 h-2 rounded-full bg-blue-500"></span>}
                            </div>

                            <pre className="text-[10px] text-neutral-600 dark:text-neutral-400 font-mono leading-relaxed bg-neutral-200/50 dark:bg-black/50 p-3 rounded-lg overflow-hidden">
                                {`query {
  user(id: "me") {
    name
    posts { title }
    friends { count }
  }
}`}
                            </pre>

                            <AnimatePresence>
                                {gqlProgress === 1 && (
                                    <motion.div
                                        initial={{ opacity: 0, height: 0 }}
                                        animate={{ opacity: 1, height: "auto" }}
                                        className="mt-3 pt-3 border-t border-neutral-200 dark:border-neutral-800 text-xs text-green-600 dark:text-green-400 font-mono flex items-center gap-2"
                                    >
                                        <FileJson2 size={14} /> Exact Payload Returned
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Copyright, Server, Database, Plus, Minus } from "lucide-react";

export default function HashingDemo() {
    const [nodes, setNodes] = useState<{ id: number; deg: number }[]>([
        { id: 1, deg: 0 },
        { id: 2, deg: 120 },
        { id: 3, deg: 240 }
    ]);

    // Generate 36 static data blocks around the 360 ring
    const [data] = useState(Array.from({ length: 36 }).map((_, i) => ({
        id: `data_${i}`,
        deg: i * 10
    })));

    const RADIUS = 140;

    const addNode = () => {
        if (nodes.length >= 6) return; // Max 6 nodes for visual sanity

        // Find largest gap to place new node
        let maxGap = 0;
        let bestDeg = 0;

        const sorted = [...nodes].sort((a, b) => a.deg - b.deg);
        for (let i = 0; i < sorted.length; i++) {
            const current = sorted[i].deg;
            const next = sorted[(i + 1) % sorted.length].deg;
            let gap = next - current;
            if (gap <= 0) gap += 360;

            if (gap > maxGap) {
                maxGap = gap;
                bestDeg = (current + gap / 2) % 360;
            }
        }

        setNodes([...nodes, { id: Date.now(), deg: bestDeg }]);
    };

    const removeNode = (idToRemove: number) => {
        if (nodes.length <= 1) return; // Must have at least 1 node
        setNodes(nodes.filter(n => n.id !== idToRemove));
    };

    // Calculate which node owns which data (Consistent Hashing logic: First node moving clockwise)
    const getAssignedNode = (dataDeg: number) => {
        const sortedNodes = [...nodes].sort((a, b) => a.deg - b.deg);
        for (const node of sortedNodes) {
            if (node.deg >= dataDeg) return node.id;
        }
        // Wrap around to first node
        return sortedNodes[0].id;
    };

    const getNodeStyles = (nodeId: number) => {
        // Deterministic highly-contrasting colors based on ID
        const colors = [
            "bg-blue-500 shadow-blue-500",
            "bg-green-500 shadow-green-500",
            "bg-purple-500 shadow-purple-500",
            "bg-orange-500 shadow-orange-500",
            "bg-pink-500 shadow-pink-500",
            "bg-cyan-500 shadow-cyan-500"
        ];
        return colors[nodeId % colors.length];
    };

    return (
        <div className="w-full bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col md:flex-row gap-8 items-center min-h-[500px]">

            {/* Context Panel */}
            <div className="w-full md:w-1/3 flex flex-col gap-6">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-2">
                        <Copyright size={20} className="text-neutral-500" />
                        The Hash Ring
                    </h3>
                    <p className="text-sm text-neutral-600 dark:text-neutral-400 leading-relaxed">
                        Data (small dots) maps to the nearest Server Node (large circles) by moving clockwise around the ring.
                    </p>
                </div>

                <div className="bg-neutral-50 dark:bg-neutral-950 border border-neutral-200 dark:border-neutral-800 rounded-xl p-5 flex flex-col gap-3">
                    <button
                        onClick={addNode}
                        disabled={nodes.length >= 6}
                        className="w-full py-2.5 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-lg text-sm font-medium flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer"
                    >
                        <Plus size={16} /> Add Server Node
                    </button>
                    <p className="text-xs text-neutral-500 text-center italic">
                        Watch how adding/removing nodes only requires moving a tiny fraction of data keys!
                    </p>
                </div>
            </div>

            {/* Visualizer */}
            <div className="w-full md:w-2/3 flex justify-center items-center py-10 relative">
                {/* The physical ring */}
                <div
                    className="absolute border-[4px] border-neutral-200 dark:border-neutral-800 rounded-full"
                    style={{ width: RADIUS * 2, height: RADIUS * 2 }}
                />

                {/* Data Keys */}
                {data.map(d => {
                    const assignedNodeId = getAssignedNode(d.deg);
                    const isWrapAround = assignedNodeId === [...nodes].sort((a, b) => a.deg - b.deg)[0].id && d.deg > [...nodes].sort((a, b) => b.deg - a.deg)[0].deg;

                    // Trig math to place on ring
                    const rad = (d.deg * Math.PI) / 180;
                    const x = Math.sin(rad) * RADIUS;
                    const y = -Math.cos(rad) * RADIUS;

                    return (
                        <motion.div
                            key={d.id}
                            className={`absolute w-3 h-3 rounded-full shadow-[0_0_10px_currentColor] transition-colors duration-1000 ${getNodeStyles(assignedNodeId)}`}
                            style={{ x, y }}
                            // The layout animation is what makes them "slide" when ownership changes
                            layout
                        />
                    );
                })}

                {/* Server Nodes */}
                <AnimatePresence>
                    {nodes.map(n => {
                        const rad = (n.deg * Math.PI) / 180;
                        const x = Math.sin(rad) * RADIUS;
                        const y = -Math.cos(rad) * RADIUS;

                        const dataOwned = data.filter(d => getAssignedNode(d.deg) === n.id).length;

                        return (
                            <motion.div
                                key={n.id}
                                initial={{ scale: 0, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1, x, y }}
                                exit={{ scale: 0, opacity: 0 }}
                                className="absolute flex flex-col items-center group z-10"
                            >
                                <div className={`w-12 h-12 rounded-full border-4 border-white dark:border-black flex items-center justify-center cursor-pointer shadow-lg hover:scale-110 transition-transform ${getNodeStyles(n.id)}`}>
                                    <Server size={20} className="text-white drop-shadow-md" />
                                </div>

                                {/* Node Stats Panel */}
                                <div className="absolute top-14 opacity-0 group-hover:opacity-100 transition-opacity bg-neutral-900 text-white text-[10px] px-3 py-2 rounded-lg whitespace-nowrap z-20 pointer-events-none flex flex-col items-center shadow-xl border border-neutral-700">
                                    <span className="font-bold mb-1">Node {n.id.toString().slice(-4)}</span>
                                    <span>{dataOwned} keys owned</span>
                                </div>

                                {/* Remove Button */}
                                {nodes.length > 1 && (
                                    <button
                                        onClick={() => removeNode(n.id)}
                                        className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-600 shadow-md cursor-pointer"
                                    >
                                        <Minus size={12} />
                                    </button>
                                )}
                            </motion.div>
                        );
                    })}
                </AnimatePresence>

            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { CreditCard, Database, Zap, ArrowRightLeft, KeyRound, Receipt, AlertCircle } from "lucide-react";

export default function IdempotencyDemo() {
    const [logs, setLogs] = useState<{ id: string, msg: string, type: "info" | "success" | "warn" | "charge", source: "client" | "server" }[]>([]);
    const [dbBalance, setDbBalance] = useState(1000);
    const [isProcessing, setIsProcessing] = useState(false);

    // The shared idempotency key for this "transaction"
    const [currentKey, setCurrentKey] = useState("idx_99fa1b2");

    // Map of processed keys
    const [idempotencyStore, setIdempotencyStore] = useState<Record<string, boolean>>({});

    const addLog = (msg: string, type: "info" | "success" | "warn" | "charge", source: "client" | "server") => {
        setLogs(prev => [...prev, { id: crypto.randomUUID(), msg, type, source }]);
    };

    const processPayment = () => {
        if (isProcessing) return;
        setIsProcessing(true);

        const reqKey = currentKey;

        // Client triggers request
        addLog(`POST /v1/charges  [Idempotency-Key: ${reqKey}]`, "info", "client");

        setTimeout(() => {
            // Server receives
            addLog(`Received checkout request with key: ${reqKey}`, "info", "server");

            setTimeout(() => {
                // Check Idempotency Store
                if (idempotencyStore[reqKey]) {
                    // Cache Hit!
                    addLog("🚨 Idempotency key exists! Skipping payment processing to prevent double-charge.", "warn", "server");
                    setTimeout(() => {
                        addLog("200 OK - Returning cached success response", "success", "server");
                        addLog("Payment successful (Cached)", "success", "client");
                        setIsProcessing(false);
                    }, 400);
                } else {
                    // Cache Miss. Process real payment.
                    addLog("Key not found. Processing real credit card charge...", "charge", "server");

                    setTimeout(() => {
                        // Deduct funds
                        setDbBalance(prev => prev - 100);

                        // Save to Idempotency Store
                        setIdempotencyStore(prev => ({ ...prev, [reqKey]: true }));

                        addLog("Charge successful. Saved key to Idempotency Store.", "success", "server");

                        setTimeout(() => {
                            addLog("200 OK - Charge Processed", "success", "server");
                            addLog("Payment successful! -$100", "success", "client");
                            setIsProcessing(false);
                        }, 400);

                    }, 800);
                }
            }, 600);
        }, 200);
    };

    const resetTransaction = () => {
        // Generate a new random idempotency key for a "new" user checkout
        setCurrentKey("idx_" + Math.random().toString(36).substring(2, 9));
        setLogs([]);
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full">
            {/* Client / Checkout View */}
            <div className="bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-[500px]">
                <div>
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2">
                            <CreditCard size={20} className="text-neutral-500" />
                            Checkout Flow
                        </h3>
                    </div>

                    <div className="bg-neutral-50 dark:bg-neutral-950 border border-neutral-200 dark:border-neutral-800 rounded-2xl p-6 mb-6">
                        <div className="flex justify-between items-end mb-6">
                            <div>
                                <p className="text-sm text-neutral-500 mb-1">Total Due</p>
                                <p className="text-3xl font-serif text-neutral-900 dark:text-white">$100.00</p>
                            </div>
                            <Receipt size={32} className="text-neutral-300 dark:text-neutral-700" />
                        </div>

                        <div className="p-3 bg-blue-50 dark:bg-blue-900/10 border border-blue-200 dark:border-blue-900/30 rounded-xl flex items-start gap-3 mb-6">
                            <AlertCircle size={16} className="text-blue-500 mt-0.5 shrink-0" />
                            <p className="text-xs text-blue-700 dark:text-blue-300 leading-relaxed">
                                Simulating a flaky network. Click &quot;Pay&quot; multiple times rapidly to simulate a user impatiently refreshing or re-submitting.
                            </p>
                        </div>

                        <div className="space-y-3">
                            <div className="flex justify-between text-xs text-neutral-500 font-mono">
                                <span>Idempotency-Key Header:</span>
                                <span>{currentKey}</span>
                            </div>
                            <button
                                onClick={processPayment}
                                disabled={isProcessing}
                                className="w-full bg-neutral-900 hover:bg-neutral-800 dark:bg-white dark:hover:bg-neutral-200 text-white dark:text-black py-3.5 rounded-xl font-medium shadow-sm active:scale-95 transition-all flex justify-center items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed cursor-pointer"
                            >
                                {isProcessing ? <Zap size={18} className="animate-pulse text-yellow-400" /> : <CreditCard size={18} />}
                                {isProcessing ? "Processing..." : "Pay $100.00"}
                            </button>
                        </div>
                    </div>
                </div>

                <button onClick={resetTransaction} className="text-sm text-neutral-500 hover:text-neutral-900 dark:hover:text-white transition-colors underline decoration-neutral-300 dark:decoration-neutral-700 cursor-pointer">
                    Start New Transaction
                </button>
            </div>

            {/* Server / Backend View */}
            <div className="bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative h-[500px]">
                <div className="flex items-center justify-between mb-4 pb-4 border-b border-neutral-800">
                    <h3 className="text-neutral-300 text-sm flex items-center gap-2">
                        <Database size={16} className="text-neutral-500" />
                        Payment Gateway Backend
                    </h3>
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 px-3 py-1 bg-neutral-800 rounded-full border border-neutral-700">
                            <KeyRound size={12} className="text-yellow-500" />
                            <span className="text-xs font-mono text-neutral-300">{Object.keys(idempotencyStore).length} stored</span>
                        </div>
                        <div className="text-sm font-mono text-green-400">
                            Merchant Balance: ${dbBalance}
                        </div>
                    </div>
                </div>

                {/* Vertical Logs */}
                <div className="flex-1 overflow-y-auto pr-2 space-y-3 scrollbar-thin scrollbar-thumb-neutral-700 scrollbar-track-transparent">
                    <AnimatePresence>
                        {logs.length === 0 && (
                            <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-neutral-600 text-sm italic m-auto text-center mt-10">
                                Awaiting payment requests...
                            </motion.p>
                        )}
                        {logs.map((log) => (
                            <motion.div
                                key={log.id}
                                initial={{ opacity: 0, x: log.source === "client" ? -20 : 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                className={`flex flex-col max-w-[90%] ${log.source === "client" ? "self-start" : "self-end ml-auto"}`}
                            >
                                <span className="text-[10px] text-neutral-500 uppercase tracking-widest pl-1 mb-0.5">
                                    {log.source === "client" ? "Client" : "Server"}
                                </span>
                                <div className={`p-3 rounded-2xl text-xs font-mono
                                    ${log.type === "info" ? "bg-neutral-800/50 text-neutral-300 border border-neutral-800" : ""}
                                    ${log.type === "success" ? "bg-green-500/10 text-green-400 border border-green-500/20" : ""}
                                    ${log.type === "warn" ? "bg-yellow-500/10 text-yellow-400 border border-yellow-500/20" : ""}
                                    ${log.type === "charge" ? "bg-indigo-500/20 text-indigo-300 border border-indigo-500/40 shadow-[0_0_15px_rgba(99,102,241,0.2)]" : ""}
                                `}>
                                    {log.type === "charge" && <Zap size={14} className="inline mr-1.5 mb-0.5 text-indigo-400" />}
                                    {log.msg}
                                </div>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Database, PlusCircle, ArrowRight, Rss, Layers, Eye, Zap, ArrowRightCircle } from "lucide-react";

type LogEvent = { id: string; type: "USER_SIGNUP" | "ORDER_PLACED" | "PAYMENT_SUCCESS" | "EMAIL_SENT"; payload: string };

export default function KafkaStreamsDemo() {
    const [events, setEvents] = useState<LogEvent[]>([]);
    const [consumerIdx, setConsumerIdx] = useState<{ analytics: number, billing: number, email: number }>({ analytics: 0, billing: 0, email: 0 });
    const [isRunning, setIsRunning] = useState(false);

    // Keep latest events in ref so intervals don't get canceled and reset every time state changes
    const eventsRef = useRef(events);
    useEffect(() => { eventsRef.current = events; }, [events]);

    // Producer simulation
    useEffect(() => {
        if (!isRunning) return;

        const interval = setInterval(() => {
            if (eventsRef.current.length > 15) {
                setIsRunning(false); // Auto-stop after a bit
                return;
            }

            const types: LogEvent["type"][] = ["USER_SIGNUP", "ORDER_PLACED", "PAYMENT_SUCCESS", "EMAIL_SENT"];
            const newEvent: LogEvent = {
                id: crypto.randomUUID(),
                type: types[Math.floor(Math.random() * types.length)],
                payload: `Data_${Math.floor(Math.random() * 1000)}`
            };

            setEvents(prev => [...prev, newEvent]);
        }, 1200);

        return () => clearInterval(interval);
    }, [isRunning]); // No events.length dependency, so interval never resets

    // Consumers pulling from log offset independently
    useEffect(() => {
        // Analytics Consumer (Fast)
        const anaTimer = setInterval(() => {
            setConsumerIdx(prev => prev.analytics < eventsRef.current.length ? { ...prev, analytics: prev.analytics + 1 } : prev);
        }, 300);

        // Billing Consumer (Medium)
        const bilTimer = setInterval(() => {
            setConsumerIdx(prev => prev.billing < eventsRef.current.length ? { ...prev, billing: prev.billing + 1 } : prev);
        }, 800);

        // Email Consumer (Slow/Lagging)
        const emTimer = setInterval(() => {
            setConsumerIdx(prev => {
                if (prev.email < eventsRef.current.length) {
                    // Randomly pretend to be slow or fail, simulating real-world backpressure
                    if (Math.random() > 0.3) {
                        return { ...prev, email: prev.email + 1 };
                    }
                }
                return prev;
            });
        }, 1500);

        return () => { clearInterval(anaTimer); clearInterval(bilTimer); clearInterval(emTimer); };

    }, []); // No state dependencies! Consumers independently poll forever, just like real Kafka consumers


    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <Layers size={20} className="text-neutral-500" />
                        Kafka Event Streams
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        Unlike traditional databases that overwrite state, Kafka is an <strong>Append-Only Log</strong>. Producers just blindly dump events onto the end of the log.
                        Independent Consumers read the log at their own pace, tracking their own "Offset".
                        <br /><br />
                        If the <i>Email Service</i> crashes for 2 hours, it just wakes up and resumes reading from its last saved offset. No data is lost!
                    </p>

                    <div className="bg-neutral-50 dark:bg-neutral-900/50 p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 mb-6">
                        <div className="flex justify-between items-center text-[10px] uppercase font-bold text-neutral-500 mb-2">
                            <span>Consumer Offsets (Lag)</span>
                        </div>
                        <div className="space-y-2 text-xs font-mono">
                            <div className="flex justify-between items-center text-blue-500">
                                <span>Analytics DB:</span>
                                <span>{consumerIdx.analytics} / {events.length}</span>
                            </div>
                            <div className="flex justify-between items-center text-emerald-500">
                                <span>Billing Svc:</span>
                                <span>{consumerIdx.billing} / {events.length}</span>
                            </div>
                            <div className="flex justify-between items-center text-orange-500">
                                <span>Email Queue:</span>
                                <span className={events.length - consumerIdx.email > 3 ? 'text-red-500 animate-pulse' : ''}>{consumerIdx.email} / {events.length}</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={() => setIsRunning(!isRunning)}
                        className={`flex-1 ${isRunning ? 'bg-red-500 hover:bg-red-600' : 'bg-indigo-500 hover:bg-indigo-600'} text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none cursor-pointer text-sm`}
                    >
                        <Zap size={16} /> {isRunning ? "Stop Producer" : "Start Producer Simulator"}
                    </button>
                    <button
                        onClick={() => { setIsRunning(false); setEvents([]); setConsumerIdx({ analytics: 0, billing: 0, email: 0 }); }}
                        className="px-6 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-xl font-medium border border-neutral-800 dark:border-neutral-200 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all outline-none cursor-pointer flex items-center justify-center disabled:opacity-50 text-sm"
                        title="Clear Log"
                    >
                        Clear
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                {/* Top: Producer Action */}
                <div className="w-full flex justify-center mb-8 relative z-20">
                    <div className="flex items-center gap-2 text-[10px] uppercase font-bold text-indigo-400 border border-indigo-500/30 bg-indigo-500/10 px-4 py-2 rounded-full">
                        <PlusCircle size={14} className={isRunning ? "animate-pulse" : ""} /> Order API (Producer)
                    </div>

                    {/* Down Arrow pointing to log */}
                    <div className="absolute top-full left-1/2 -translate-x-1/2 mt-2 text-neutral-600">
                        <ArrowRightCircle size={16} className="rotate-90" />
                    </div>
                </div>

                {/* Middle: The Append-Only Log Array (Immutable) */}
                <div className="flex-1 w-full bg-neutral-800/50 rounded-xl border-x-4 border-b-4 border-neutral-700 relative overflow-hidden flex flex-col mt-4">

                    <div className="absolute top-2 left-4 text-[10px] uppercase font-bold tracking-widest text-neutral-500 flex items-center gap-2">
                        <Layers size={14} /> Immutable Event Log (Topic: 'orders')
                    </div>

                    {/* Events scrolling left */}
                    <div className="flex-1 flex items-center gap-2 px-4 overflow-x-hidden mt-6 relative w-full justify-end">
                        <AnimatePresence>
                            {events.map((evt, i) => (
                                <motion.div
                                    key={evt.id}
                                    initial={{ x: 50, opacity: 0, scale: 0.8 }}
                                    animate={{ x: 0, opacity: 1, scale: 1 }}
                                    className="min-w-[120px] h-20 rounded-lg border border-neutral-600 bg-neutral-800 flex flex-col items-center justify-center relative shrink-0 shadow-lg"
                                >
                                    <span className="absolute -top-3 -left-2 bg-neutral-900 px-1 border border-neutral-700 rounded text-[8px] text-neutral-500 font-bold font-mono">
                                        offset:{i}
                                    </span>
                                    <span className={`text-[9px] font-bold px-2 py-0.5 rounded uppercase ${evt.type === 'USER_SIGNUP' ? 'bg-cyan-500/20 text-cyan-400' :
                                        evt.type === 'ORDER_PLACED' ? 'bg-indigo-500/20 text-indigo-400' :
                                            evt.type === 'PAYMENT_SUCCESS' ? 'bg-emerald-500/20 text-emerald-400' :
                                                'bg-orange-500/20 text-orange-400'
                                        }`}>
                                        {evt.type}
                                    </span>
                                    <span className="text-[10px] mt-2 text-neutral-400">{evt.payload}</span>
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>
                </div>

                {/* Bottom: Consumers tracking their offsets */}
                <div className="w-full flex justify-between mt-8 relative z-20 px-8">

                    <div className="flex flex-col items-center gap-2">
                        <div className="flex items-center gap-1 text-[10px] font-bold text-blue-400 bg-blue-900/20 px-2 py-1 rounded border border-blue-500/30">
                            <Database size={12} /> Analytics
                        </div>
                        <div className="bg-neutral-800 border border-neutral-700 px-2 py-0.5 rounded text-[10px]">idx: {consumerIdx.analytics}</div>
                    </div>

                    <div className="flex flex-col items-center gap-2">
                        <div className="flex items-center gap-1 text-[10px] font-bold text-emerald-400 bg-emerald-900/20 px-2 py-1 rounded border border-emerald-500/30">
                            <Zap size={12} /> Billing
                        </div>
                        <div className="bg-neutral-800 border border-neutral-700 px-2 py-0.5 rounded text-[10px]">idx: {consumerIdx.billing}</div>
                    </div>

                    <div className="flex flex-col items-center gap-2">
                        <div className={`flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded border ${events.length - consumerIdx.email > 3 ? 'text-red-400 bg-red-900/20 border-red-500/30 shadow-[0_0_15px_rgba(239,68,68,0.5)]' : 'text-orange-400 bg-orange-900/20 border-orange-500/30'}`}>
                            <Rss size={12} /> Email
                        </div>
                        <div className="bg-neutral-800 border border-neutral-700 px-2 py-0.5 rounded text-[10px]">idx: {consumerIdx.email}</div>
                    </div>

                </div>

                {/* Visual Pointers connecting Consumers to the Log Array */}
                {/* (Simulated roughly with SVG depending on offset diffs) */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none -z-10 opacity-30">
                    {/* Paths drawn based on visual lag distance - abstract representation */}
                    {events.length > 0 && (
                        <>
                            <line x1="20%" y1="90%" x2={`${90 - (events.length - consumerIdx.analytics) * 5}%`} y2="60%" stroke="#60a5fa" strokeWidth="2" strokeDasharray="4 4" />
                            <line x1="50%" y1="90%" x2={`${90 - (events.length - consumerIdx.billing) * 5}%`} y2="60%" stroke="#34d399" strokeWidth="2" strokeDasharray="4 4" />
                            <line x1="80%" y1="90%" x2={`${90 - (events.length - consumerIdx.email) * 5}%`} y2="60%" stroke="#fb923c" strokeWidth="2" strokeDasharray="4 4" />
                        </>
                    )}
                </svg>

            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Server, Zap, HeartPulse, UserSquare2, RefreshCcw, Skull } from "lucide-react";

type Role = "follower" | "candidate" | "leader" | "dead";
type Stage = "idle" | "election" | "voting" | "heartbeating" | "killed";

export default function LeaderElectionDemo() {
    const [roles, setRoles] = useState<Record<number, Role>>({
        1: "follower", 2: "follower", 3: "follower", 4: "follower", 5: "follower"
    });
    const [stage, setStage] = useState<Stage>("idle");
    const [logs, setLogs] = useState<{ id: string; msg: string; type: "info" | "success" | "warn" | "error" | "pulse" }[]>([]);

    // To position nodes in a rough circle around center (Node 1 is top, etc)
    const positions = {
        1: { top: "10%", left: "50%", transform: "translate(-50%, 0)" },
        2: { top: "40%", left: "15%", transform: "translate(0, -50%)" },
        3: { top: "40%", right: "15%", transform: "translate(0, -50%)" },
        4: { bottom: "10%", left: "30%", transform: "translate(-50%, 0)" },
        5: { bottom: "10%", right: "30%", transform: "translate(50%, 0)" },
    };

    const addLog = (msg: string, type: "info" | "success" | "warn" | "error" | "pulse") => {
        setLogs(prev => [{ id: crypto.randomUUID(), msg, type }, ...prev].slice(0, 5));
    };

    const triggerElection = async (candidateId: number) => {
        if (stage !== "idle" && stage !== "killed") return;

        setStage("election");
        setLogs([]);
        setRoles({ 1: "follower", 2: "follower", 3: "follower", 4: "follower", 5: "follower", [candidateId]: "candidate" });

        await new Promise(r => setTimeout(r, 400));
        addLog(`Node ${candidateId}: Election timeout! Becoming Candidate.`, "warn");
        addLog(`Node ${candidateId}: Term incremented. Sending RequestVote RPCs...`, "info");

        await new Promise(r => setTimeout(r, 1200));
        setStage("voting");

        const aliveNodes = [1, 2, 3, 4, 5].filter(n => n !== candidateId);
        addLog(`Nodes [${aliveNodes.join(',')}] granted vote to Node ${candidateId}.`, "success");

        await new Promise(r => setTimeout(r, 1200));

        setRoles(prev => ({ ...prev, [candidateId]: "leader" }));
        setStage("heartbeating");
        addLog(`Node ${candidateId}: Won election! I am the new Leader.`, "success");

        // Heartbeats
        await new Promise(r => setTimeout(r, 1000));
        addLog(`Leader ${candidateId}: Sending AppendEntries (Heartbeat)...`, "pulse");
        await new Promise(r => setTimeout(r, 1500));
        if (stage !== "killed") {
            addLog(`Leader ${candidateId}: Sending AppendEntries (Heartbeat)...`, "pulse");
        }
    };

    const killLeader = () => {
        const leaderId = Object.keys(roles).find(k => roles[parseInt(k)] === "leader");
        if (leaderId) {
            setRoles(prev => ({ ...prev, [parseInt(leaderId)]: "dead" }));
            setStage("killed");
            addLog(`Leader ${leaderId} CRASHED! Heartbeats stopped.`, "error");
        }
    };

    const resetCluster = () => {
        setRoles({ 1: "follower", 2: "follower", 3: "follower", 4: "follower", 5: "follower" });
        setStage("idle");
        setLogs([]);
    };

    const isRunning = stage === "election" || stage === "voting";
    const hasLeader = Object.values(roles).includes("leader");
    const leaderId = Object.keys(roles).find(k => roles[parseInt(k)] === "leader");
    const candidateId = Object.keys(roles).find(k => roles[parseInt(k)] === "candidate");

    const activeCentralNode = leaderId || candidateId;

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <UserSquare2 size={20} className="text-neutral-500" />
                        Leader Election (Raft)
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        In distributed databases, nodes must agree on who handles writes. Raft uses a randomized "Election Timeout". If a Follower stops hearing heartbeats, it becomes a Candidate and requests votes. A majority wins the Leadership.
                    </p>

                    <div className="space-y-3 mb-8">
                        <button
                            onClick={() => triggerElection(Math.floor(Math.random() * 5) + 1)}
                            disabled={isRunning || hasLeader}
                            className="w-full bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-200 dark:border-indigo-900/40 text-indigo-700 dark:text-indigo-400 py-3 rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-indigo-100 dark:hover:bg-indigo-900/40 transition-all disabled:opacity-40 outline-none cursor-pointer text-xs"
                        >
                            <Zap size={16} /> Simulate Election Timeout
                        </button>

                        <button
                            onClick={killLeader}
                            disabled={!hasLeader}
                            className="w-full bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900/40 text-red-700 dark:text-red-400 py-3 rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-red-100 dark:hover:bg-red-900/40 transition-all disabled:opacity-40 outline-none cursor-pointer text-xs"
                        >
                            <Skull size={16} /> Crash the Leader
                        </button>
                    </div>
                </div>

                <button
                    onClick={resetCluster}
                    disabled={isRunning}
                    className="w-full bg-neutral-900 dark:bg-white text-white dark:text-black py-4 rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all disabled:opacity-50 cursor-pointer text-sm"
                >
                    <RefreshCcw size={16} /> Reset Cluster
                </button>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                <div className="flex-1 relative z-10 w-full max-w-lg mx-auto mt-4 px-4 py-8 pointer-events-none">

                    {[1, 2, 3, 4, 5].map(id => {
                        const role = roles[id];
                        const pos = (positions as any)[id];

                        return (
                            <div key={id} className="absolute flex flex-col items-center gap-2 transition-all duration-500" style={pos}>

                                <div className={`w-14 h-14 rounded-2xl border-2 flex flex-col items-center justify-center relative z-20 transition-all duration-300 ${role === 'leader' ? 'bg-indigo-500 border-indigo-300 shadow-[0_0_30px_rgba(99,102,241,0.5)] scale-110' :
                                        role === 'candidate' ? 'bg-yellow-500 border-yellow-300 shadow-[0_0_20px_rgba(250,204,21,0.5)] scale-110' :
                                            role === 'dead' ? 'bg-neutral-900 border-red-500/50 opacity-50 grayscale' :
                                                'bg-neutral-800 border-neutral-700 opacity-80'
                                    }`}>

                                    {role === 'leader' ? <UserSquare2 size={24} className="text-white" /> :
                                        role === 'candidate' ? <UserSquare2 size={24} className="text-yellow-900" /> :
                                            role === 'dead' ? <Skull size={24} className="text-red-500" /> :
                                                <Server size={24} className="text-neutral-500" />}

                                    {/* Vote Request Animation (Outgoing) */}
                                    <AnimatePresence>
                                        {role === 'candidate' && stage === 'election' && (
                                            <motion.div initial={{ scale: 0, opacity: 1 }} animate={{ scale: 5, opacity: 0 }} transition={{ duration: 1.5, repeat: Infinity }} className="absolute inset-0 rounded-2xl border-2 border-yellow-400 pointer-events-none" />
                                        )}
                                    </AnimatePresence>
                                </div>

                                <span className={`text-[10px] uppercase font-bold tracking-widest ${role === 'leader' ? 'text-indigo-400' :
                                        role === 'candidate' ? 'text-yellow-400' :
                                            role === 'dead' ? 'text-red-500' :
                                                'text-neutral-500'
                                    }`}>
                                    {role === 'leader' ? 'Leader' : role === 'candidate' ? 'Candidate' : role === 'dead' ? 'Dead' : 'Follower'}
                                </span>
                            </div>
                        )
                    })}

                    {/* Central Animations Overlay */}
                    <div className="absolute inset-0 z-0 flex items-center justify-center">
                        <AnimatePresence>
                            {/* Heartbeats (Leader -> Followers) */}
                            {stage === 'heartbeating' && leaderId && (
                                <motion.div
                                    initial={{ scale: 0, opacity: 1 }}
                                    animate={{ scale: 3.5, opacity: 0 }}
                                    transition={{ duration: 1.5, repeat: Infinity }}
                                    className="absolute inset-0 m-auto w-32 h-32 rounded-full border-2 border-indigo-500 shadow-[inset_0_0_20px_rgba(99,102,241,0.3)] bg-indigo-500/5 mix-blend-screen"
                                    style={{
                                        // offset to start roughly from the leader's position if we wanted to be perfectly precise,
                                        // but a central wave emitting from the middle looks great abstractly for a cluster heartbeat.
                                    }}
                                >
                                    <div className="absolute inset-0 flex items-center justify-center text-indigo-400 opacity-50">
                                        <HeartPulse size={48} />
                                    </div>
                                </motion.div>
                            )}

                            {/* Votes Returning (Followers -> Candidate) */}
                            {stage === 'voting' && candidateId && (
                                <motion.div
                                    initial={{ scale: 4, opacity: 0 }}
                                    animate={{ scale: 0, opacity: 1 }}
                                    transition={{ duration: 1 }}
                                    className="absolute inset-0 m-auto w-32 h-32 rounded-full border-2 border-emerald-400 border-dashed"
                                />
                            )}
                        </AnimatePresence>
                    </div>

                </div>

                {/* Logs */}
                <div className="h-32 bg-black border-t border-neutral-800 p-4 font-mono text-[11px] overflow-y-auto z-30 shrink-0">
                    <AnimatePresence>
                        {logs.length === 0 && <span className="text-neutral-600">All nodes are healthy followers. Standing by...</span>}
                        {logs.map((log) => (
                            <motion.div
                                key={log.id}
                                initial={{ opacity: 0, x: -5 }} animate={{ opacity: 1, x: 0 }}
                                className={`mb-1 flex gap-2 ${log.type === 'error' ? 'text-red-400' :
                                        log.type === 'success' ? 'text-green-400' :
                                            log.type === 'warn' ? 'text-yellow-400' :
                                                log.type === 'pulse' ? 'text-indigo-400' :
                                                    'text-neutral-300'
                                    }`}
                            >
                                <span className="opacity-50 shrink-0">{log.type === 'pulse' ? '~' : '>'}</span>
                                <span>{log.msg}</span>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Server, ArrowRight, Zap } from "lucide-react";

interface RequestLog {
    id: string;
    node: "A" | "B" | "C";
    timestamp: Date;
}

export default function LoadBalancerDemo() {
    const [requestLog, setRequestLog] = useState<RequestLog[]>([]);
    const [activeNode, setActiveNode] = useState<"A" | "B" | "C" | null>(null);
    const [isHovering, setIsHovering] = useState(false);

    // Round Robin Logic
    const nodes: ("A" | "B" | "C")[] = ["A", "B", "C"];
    const [currentIndex, setCurrentIndex] = useState(0);

    const handleRequest = () => {
        const timestamp = new Date();
        const id = crypto.randomUUID();
        const assignedNode = nodes[currentIndex];

        // Animate the active node
        setActiveNode(assignedNode);
        setTimeout(() => setActiveNode(null), 300);

        // Update Log
        setRequestLog((prev) => [{ id, node: assignedNode, timestamp }, ...prev].slice(0, 10));

        // Advance Round Robin Index
        setCurrentIndex((prev) => (prev + 1) % nodes.length);
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full">
            {/* Control Panel & Visualization */}
            <div className="bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between">
                <div>
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2">
                            <Server size={20} className="text-neutral-500" />
                            Load Balancer
                        </h3>
                        <span className="text-xs font-mono bg-neutral-100 dark:bg-neutral-800 px-2 py-1 rounded text-neutral-500">Round Robin</span>
                    </div>

                    {/* Nodes Visualization */}
                    <div className="flex flex-col gap-4 mb-8">
                        {nodes.map((node) => (
                            <div
                                key={node}
                                className={`flex items-center justify-between p-4 rounded-xl border transition-all duration-300 ${activeNode === node
                                    ? "bg-blue-50 dark:bg-blue-900/20 border-blue-400 dark:border-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.3)]"
                                    : "bg-neutral-50 dark:bg-neutral-800/50 border-neutral-200 dark:border-neutral-700"
                                    }`}
                            >
                                <div className="flex items-center gap-3">
                                    <Server size={18} className={activeNode === node ? "text-blue-500" : "text-neutral-400"} />
                                    <span className={`font-mono font-medium ${activeNode === node ? "text-blue-600 dark:text-blue-400" : "text-neutral-600 dark:text-neutral-400"}`}>
                                        Node {node}
                                    </span>
                                </div>
                                <div className="flex items-center gap-2">
                                    <span className={`h-2 w-2 rounded-full ${activeNode === node ? "bg-blue-500 animate-pulse" : "bg-neutral-300 dark:bg-neutral-600"}`}></span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Action Button */}
                <button
                    onClick={handleRequest}
                    onMouseEnter={() => setIsHovering(true)}
                    onMouseLeave={() => setIsHovering(false)}
                    style={isHovering ? { transform: "translateY(-2px)" } : {}}
                    className="w-full relative group overflow-hidden bg-neutral-900 dark:bg-white text-white dark:text-black py-4 px-6 rounded-full font-medium transition-all active:scale-95 flex items-center justify-center gap-2 shadow-lg hover:shadow-xl cursor-pointer"
                >
                    <Zap size={18} className={`${isHovering ? "text-blue-400 dark:text-blue-500" : ""}`} />
                    <span className="relative z-10">Send Traffic</span>
                    {/* Hover effect */}
                    <div className="absolute inset-0 bg-black/10 dark:bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity" />
                </button>
            </div>

            {/* Terminal / Log */}
            <div className="bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col font-mono relative overflow-hidden h-[350px]">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-blue-500/50 to-transparent opacity-50"></div>

                <div className="flex items-center justify-between mb-4 pb-4 border-b border-neutral-800">
                    <span className="text-neutral-400 text-sm">lb-proxy.log</span>
                    <span className="text-neutral-500 text-xs">upstream routing</span>
                </div>

                <div className="flex-1 overflow-hidden relative">
                    <div className="absolute inset-0 overflow-y-auto pr-2 space-y-3 pb-4 scrollbar-thin scrollbar-thumb-neutral-700 scrollbar-track-transparent">
                        <AnimatePresence initial={false}>
                            {requestLog.length === 0 && (
                                <motion.p
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    className="text-neutral-600 text-sm italic"
                                >
                                    Waiting for incoming traffic...
                                </motion.p>
                            )}

                            {requestLog.map((log) => (
                                <motion.div
                                    key={log.id}
                                    initial={{ opacity: 0, x: -10 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    className="text-sm flex items-start gap-3"
                                >
                                    <span className="text-neutral-500 shrink-0">
                                        {log.timestamp.toLocaleTimeString([], { hour12: false, second: '2-digit', fractionalSecondDigits: 3 })}
                                    </span>

                                    <div className="flex items-center gap-2 text-neutral-300">
                                        <span>Req routed</span>
                                        <ArrowRight size={12} className="text-neutral-600" />
                                        <span className="text-blue-400 font-bold">Node {log.node}</span>
                                    </div>
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Database, Filter, ArrowRight, Layers, FileDown, Play, RotateCcw } from "lucide-react";

type Stage = "idle" | "split" | "map" | "shuffle" | "reduce" | "done";

export default function MapReduceDemo() {
    const [stage, setStage] = useState<Stage>("idle");

    // The raw input dataset (Word Count example)
    const rawData = ["apple banana", "apple orange", "banana apple"];

    const runPipeline = async () => {
        if (stage !== "idle" && stage !== "done") return;

        setStage("idle");
        await new Promise(r => setTimeout(r, 400));

        // 1. Split
        setStage("split");
        await new Promise(r => setTimeout(r, 1500));

        // 2. Map (parallel processing)
        setStage("map");
        await new Promise(r => setTimeout(r, 2000));

        // 3. Shuffle (group by key over network)
        setStage("shuffle");
        await new Promise(r => setTimeout(r, 2000));

        // 4. Reduce (aggregate)
        setStage("reduce");
        await new Promise(r => setTimeout(r, 2000));

        // 5. Done (output)
        setStage("done");
    };

    const isRunning = stage !== "idle" && stage !== "done";

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <Layers size={20} className="text-neutral-500" />
                        MapReduce Pipeline
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        How do you process 50 Terabytes of text to find word frequencies? You can't fit it on one machine. MapReduce <i>splits</i> the data, <i>maps</i> (transforms) chunks in parallel across hundreds of cheap workers, <i>shuffles</i> identical keys together, and <i>reduces</i> them into a final answer.
                    </p>

                    <div className="bg-neutral-50 dark:bg-neutral-900/50 p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 mb-6">
                        <span className="text-neutral-500 text-[10px] uppercase font-bold tracking-widest block mb-2">Target Problem: Word Count</span>
                        <div className="text-xs font-mono space-y-1 text-neutral-700 dark:text-neutral-300 bg-white dark:bg-black p-2 rounded border border-neutral-200 dark:border-neutral-700">
                            {rawData.map((line, i) => <div key={i}>{i + 1}. {line}</div>)}
                        </div>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={runPipeline}
                        disabled={isRunning}
                        className="flex-1 bg-indigo-500 hover:bg-indigo-600 text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none disabled:opacity-50 cursor-pointer text-sm"
                    >
                        <Play size={16} /> Execute Job
                    </button>
                    <button
                        onClick={() => setStage("idle")}
                        disabled={isRunning}
                        className="px-6 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-xl font-medium border border-neutral-800 dark:border-neutral-200 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all outline-none cursor-pointer flex items-center justify-center disabled:opacity-50 text-sm"
                        title="Reset"
                    >
                        <RotateCcw size={16} />
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
