"use client";

import { useEffect, useRef } from "react";

// Add your skin files to public/oneko/ and list them here
const SKINS = [
    "/oneko/oneko.gif",
    "/oneko/oneko-dog.gif",
    "/oneko/oneko-tora.gif",
    "/oneko/oneko-maia.gif",
    "/oneko/oneko-vaporwave.gif",
];

const Oneko = ({
    initialPos = { x: 32, y: 32 },
    targetOffset = { x: 0, y: 0 }
}: {
    initialPos?: { x: number, y: number },
    targetOffset?: { x: number, y: number }
}) => {
    const nekoRef = useRef<HTMLDivElement>(null);
    const posRef = useRef(initialPos);
    const mouseRef = useRef({ x: 0, y: 0 });
    const frameRef = useRef(0);
    const idleTimeRef = useRef(0);
    const idleAnimationRef = useRef<string | null>(null);
    const idleAnimationFrameRef = useRef(0);
    const lastFrameTimestampRef = useRef<number>(0);
    const requestRef = useRef<number>(0);

    const isDraggingRef = useRef(false);
    const dragOffsetRef = useRef({ x: 0, y: 0 });

    // Select skin once on mount
    const skinRef = useRef("/oneko/oneko.gif");

    useEffect(() => {
        // Randomly select a skin on mount (client-side only to avoid hydration mismatch if using random)
        // Since this runs in useEffect, it's safe.
        skinRef.current = SKINS[Math.floor(Math.random() * SKINS.length)];

        const isReducedMotion = window.matchMedia(`(prefers-reduced-motion: reduce)`).matches;
        if (isReducedMotion) return;

        const nekoEl = nekoRef.current;
        if (!nekoEl) return;

        // Apply the selected skin
        nekoEl.style.backgroundImage = `url('${skinRef.current}')`;

        // Randomize initial idle time so they don't all sleep/scratch at once
        idleTimeRef.current = Math.floor(Math.random() * 10);


        const nekoSpeed = 10;
        const spriteSets: { [key: string]: number[][] } = {
            idle: [[-3, -3]],
            alert: [[-7, -3]],
            scratchSelf: [[-5, 0], [-6, 0], [-7, 0]],
            scratchWallN: [[0, 0], [0, -1]],
            scratchWallS: [[-7, -1], [-6, -2]],
            scratchWallE: [[-2, -2], [-2, -3]],
            scratchWallW: [[-4, 0], [-4, -1]],
            tired: [[-3, -2]],
            sleeping: [[-2, 0], [-2, -1]],
            N: [[-1, -2], [-1, -3]],
            NE: [[0, -2], [0, -3]],
            E: [[-3, 0], [-3, -1]],
            SE: [[-5, -1], [-5, -2]],
            S: [[-6, -3], [-7, -2]],
            SW: [[-5, -3], [-6, -1]],
            W: [[-4, -2], [-4, -3]],
            NW: [[-1, 0], [-1, -1]],
        };

        function setSprite(name: string, frame: number) {
            const sprite = spriteSets[name][frame % spriteSets[name].length];
            if (nekoEl) {
                nekoEl.style.backgroundPosition = `${sprite[0] * 32}px ${sprite[1] * 32}px`;
            }
        }

        function resetIdleAnimation() {
            idleAnimationRef.current = null;
            idleAnimationFrameRef.current = 0;
        }

        function idle() {
            idleTimeRef.current += 1;

            // every ~ 20 seconds
            if (
                idleTimeRef.current > 10 &&
                Math.floor(Math.random() * 200) === 0 &&
                idleAnimationRef.current === null
            ) {
                let availableIdleAnimations = ["sleeping", "scratchSelf"];
                if (posRef.current.x < 32) availableIdleAnimations.push("scratchWallW");
                if (posRef.current.y < 32) availableIdleAnimations.push("scratchWallN");
                if (posRef.current.x > window.innerWidth - 32) availableIdleAnimations.push("scratchWallE");
                if (posRef.current.y > window.innerHeight - 32) availableIdleAnimations.push("scratchWallS");
                idleAnimationRef.current = availableIdleAnimations[Math.floor(Math.random() * availableIdleAnimations.length)];
            }

            switch (idleAnimationRef.current) {
                case "sleeping":
                    if (idleAnimationFrameRef.current < 8) {
                        setSprite("tired", 0);
                        break;
                    }
                    setSprite("sleeping", Math.floor(idleAnimationFrameRef.current / 4));
                    if (idleAnimationFrameRef.current > 192) {
                        resetIdleAnimation();
                    }
                    break;
                case "scratchWallN":
                case "scratchWallS":
                case "scratchWallE":
                case "scratchWallW":
                case "scratchSelf":
                    setSprite(idleAnimationRef.current, idleAnimationFrameRef.current);
                    if (idleAnimationFrameRef.current > 9) {
                        resetIdleAnimation();
                    }
                    break;
                default:
                    setSprite("idle", 0);
                    return;
            }
            idleAnimationFrameRef.current += 1;
        }

        function frame() {
            // Skip autonomous movement if dragging
            if (isDraggingRef.current) {
                if (nekoEl) {
                    nekoEl.style.left = `${posRef.current.x - 16}px`;
                    nekoEl.style.top = `${posRef.current.y - 16}px`;
                    setSprite("scratchSelf", 0);
                }
                return;
            }

            frameRef.current += 1;

            // Target is mouse position + offset
            const targetX = mouseRef.current.x + targetOffset.x;
            const targetY = mouseRef.current.y + targetOffset.y;

            const diffX = posRef.current.x - targetX;
            const diffY = posRef.current.y - targetY;
            const distance = Math.sqrt(diffX ** 2 + diffY ** 2);

            if (distance < nekoSpeed || distance < 48) {
                idle();
                return;
            }

            idleAnimationRef.current = null;
            idleAnimationFrameRef.current = 0;

            if (idleTimeRef.current > 1) {
                setSprite("alert", 0);
                idleTimeRef.current = Math.min(idleTimeRef.current, 7);
                idleTimeRef.current -= 1;
                return;
            }

            let direction = "";
            direction = diffY / distance > 0.5 ? "N" : "";
            direction += diffY / distance < -0.5 ? "S" : "";
            direction += diffX / distance > 0.5 ? "W" : "";
            direction += diffX / distance < -0.5 ? "E" : "";
            setSprite(direction, frameRef.current);

            posRef.current.x -= (diffX / distance) * nekoSpeed;
            posRef.current.y -= (diffY / distance) * nekoSpeed;

            posRef.current.x = Math.min(Math.max(16, posRef.current.x), window.innerWidth - 16);
            posRef.current.y = Math.min(Math.max(16, posRef.current.y), window.innerHeight - 16);

            if (nekoEl) {
                nekoEl.style.left = `${posRef.current.x - 16}px`;
                nekoEl.style.top = `${posRef.current.y - 16}px`;
            }
        }

        const onAnimationFrame = (timestamp: number) => {
            if (!lastFrameTimestampRef.current) {
                lastFrameTimestampRef.current = timestamp;
            }
            if (timestamp - lastFrameTimestampRef.current > 100) {
                lastFrameTimestampRef.current = timestamp;
                frame();
            }
            requestRef.current = window.requestAnimationFrame(onAnimationFrame);
        };

        const handleMouseMove = (event: MouseEvent) => {
            mouseRef.current.x = event.clientX;
            mouseRef.current.y = event.clientY;

            if (isDraggingRef.current) {
                const newX = event.clientX - dragOffsetRef.current.x;
                const newY = event.clientY - dragOffsetRef.current.y;
                posRef.current.x = newX + 16;
                posRef.current.y = newY + 16;
            }
        };

        const handleMouseDown = (event: MouseEvent) => {
            if (event.button !== 0) return;
            event.preventDefault();

            isDraggingRef.current = true;

            const rect = nekoEl.getBoundingClientRect();
            dragOffsetRef.current = {
                x: event.clientX - rect.left,
                y: event.clientY - rect.top
            };
        };

        const handleMouseUp = () => {
            isDraggingRef.current = false;
        };

        document.addEventListener("mousemove", handleMouseMove);
        document.addEventListener("mouseup", handleMouseUp);
        nekoEl.addEventListener("mousedown", handleMouseDown);

        requestRef.current = window.requestAnimationFrame(onAnimationFrame);

        return () => {
            document.removeEventListener("mousemove", handleMouseMove);
            document.removeEventListener("mouseup", handleMouseUp);
            if (nekoEl) nekoEl.removeEventListener("mousedown", handleMouseDown);

            if (requestRef.current) {
                window.cancelAnimationFrame(requestRef.current);
            }
        };
    }, [targetOffset]);

    const clickCountRef = useRef(0);
    const clickTimeoutRef = useRef<NodeJS.Timeout | null>(null);

    const handleNekoClick = () => {
        clickCountRef.current += 1;

        if (clickTimeoutRef.current) {
            clearTimeout(clickTimeoutRef.current);
        }

        // Reset click count after 2 seconds of inactivity
        clickTimeoutRef.current = setTimeout(() => {
            clickCountRef.current = 0;
        }, 2000);

        if (clickCountRef.current >= 5) {
            clickCountRef.current = 0;
            // Dispatch a custom event to notify the parent/app
            const event = new CustomEvent('matrix-mode-activated');
            window.dispatchEvent(event);
        }
    };

    return (
        <div
            ref={nekoRef}
            aria-hidden="true"
            className="mascot-container"
            onClick={handleNekoClick}
            style={{
                width: "32px",
                height: "32px",
                position: "fixed",
                pointerEvents: "auto",
                cursor: "pointer", // Changed to pointer for click affordance
                imageRendering: "pixelated",
                left: `${initialPos.x - 16}px`,
                top: `${initialPos.y - 16}px`,
                zIndex: 9999,
                // backgroundImage set in useEffect
            }}
        />
    );
};

export default function Mascot() {
    return (
        <Oneko initialPos={{ x: 32, y: 32 }} targetOffset={{ x: 0, y: 0 }} />
    );
}

"use client";

import React, { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { ExternalLink, BookOpen, Calendar } from "lucide-react";

interface MediumArticle {
    title: string;
    pubDate: string;
    link: string;
    thumbnail: string;
    description: string;
    categories: string[];
}

export default function MediumArticles() {
    const [articles, setArticles] = useState<MediumArticle[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    // Hardcode the Medium profile name or pass it via props/data
    const username = "@omsingh8400";
    const rssUrl = `https://medium.com/feed/${username}`;
    // We use rss2json to convert the XML feed to JSON
    const apiUrl = `https://api.rss2json.com/v1/api.json?rss_url=${rssUrl}`;

    useEffect(() => {
        const fetchArticles = async () => {
            try {
                const response = await fetch(apiUrl);
                if (!response.ok) {
                    throw new Error("Failed to fetch Medium articles");
                }
                const data = await response.json();

                // Extract only the top 3 articles
                const latestArticles = data.items.slice(0, 3).map((item: any) => {
                    // Remove HTML tags from the description for a cleaner snippet
                    const plainTextDescription = item.description
                        .replace(/<[^>]+>/g, '')
                        .replace(/&nbsp;/g, ' ')
                        .trim();

                    return {
                        title: item.title,
                        pubDate: new Date(item.pubDate).toLocaleDateString("en-US", {
                            year: "numeric",
                            month: "short",
                            day: "numeric",
                        }),
                        link: item.link,
                        thumbnail: item.thumbnail,
                        // Provide a short fallback if the description is weird
                        description: plainTextDescription.substring(0, 150) + "...",
                        categories: item.categories || [],
                    };
                });

                setArticles(latestArticles);
                setLoading(false);
            } catch (err: any) {
                console.error(err);
                setError(err.message || "Something went wrong");
                setLoading(false);
            }
        };

        fetchArticles();
    }, [apiUrl]);

    if (error || (articles.length === 0 && !loading)) {
        return null; // Silently hide the section if there's no data or an error
    }

    return (
        <section id="articles" className="py-24 md:py-32 flex justify-center bg-white dark:bg-black overflow-hidden relative w-full">
            <div className="max-w-6xl w-full px-6 grid grid-cols-1 md:grid-cols-12 gap-12 md:gap-20 items-center">
                <div className="md:col-span-12 max-w-4xl mx-auto w-full">

                    {/* Header */}
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.8, ease: "easeOut" }}
                        className="text-center mb-16"
                    >
                        <div className="flex items-center justify-center gap-4 mb-12">
                            <div className="h-px w-12 bg-neutral-900 dark:bg-white" />
                            <span className="text-sm font-medium tracking-widest uppercase text-neutral-900 dark:text-white">
                                Latest Articles
                            </span>
                            <div className="h-px w-12 bg-neutral-900 dark:bg-white" />
                        </div>
                    </motion.div>

                    {/* Articles Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        {loading
                            ? // Skeletons
                            Array.from({ length: 3 }).map((_, i) => (
                                <div
                                    key={i}
                                    className="h-96 w-full animate-pulse bg-neutral-100 dark:bg-neutral-900 rounded-[2rem]"
                                />
                            ))
                            : articles.map((article, idx) => (
                                <motion.a
                                    key={idx}
                                    href={article.link}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    initial={{ opacity: 0, y: 20 }}
                                    whileInView={{ opacity: 1, y: 0 }}
                                    viewport={{ once: true }}
                                    transition={{ duration: 0.5, delay: idx * 0.1 }}
                                    className="group relative flex flex-col justify-between h-full bg-neutral-50 dark:bg-neutral-900/50 rounded-[2rem] p-8 hover:bg-neutral-100 dark:hover:bg-neutral-900 transition-all duration-500 overflow-hidden border border-neutral-200/50 dark:border-neutral-800/50 hover:border-neutral-300 dark:hover:border-neutral-700"
                                >
                                    {/* Hover Glow */}
                                    <div className="absolute inset-0 bg-gradient-to-br from-neutral-200/0 via-neutral-100/0 to-neutral-200/50 dark:from-neutral-800/0 dark:via-neutral-900/0 dark:to-neutral-800/50 opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-[2rem]" />

                                    <div className="relative z-10">
                                        {/* Fallback pattern if thumbnail is missing */}
                                        {article.thumbnail ? (
                                            <div className="w-full h-40 mb-6 rounded-xl overflow-hidden bg-neutral-200 dark:bg-neutral-800">
                                                <img
                                                    src={article.thumbnail}
                                                    alt={article.title}
                                                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                                                />
                                            </div>
                                        ) : (
                                            <div className="w-12 h-12 bg-neutral-200 dark:bg-neutral-800 rounded-xl flex items-center justify-center mb-6">
                                                <BookOpen className="text-neutral-500 dark:text-neutral-400" size={24} />
                                            </div>
                                        )}

                                        <div className="flex items-center gap-2 text-xs font-medium text-neutral-500 dark:text-neutral-400 mb-4">
                                            <Calendar size={14} />
                                            <span>{article.pubDate}</span>
                                        </div>

                                        <h3 className="text-xl font-serif font-bold text-neutral-900 dark:text-white mb-3 leading-tight group-hover:text-black dark:group-hover:text-white/90 transition-colors">
                                            {article.title}
                                        </h3>

                                        <p className="text-sm text-neutral-600 dark:text-neutral-400 leading-relaxed mb-6 line-clamp-3">
                                            {article.description}
                                        </p>
                                    </div>

                                    <div className="relative z-10 flex items-center gap-2 text-sm font-medium text-black dark:text-white group/btn mt-auto pt-4 border-t border-neutral-200 dark:border-neutral-800">
                                        <span>Read Article</span>
                                        <ExternalLink size={16} className="group-hover/btn:translate-x-1 group-hover/btn:-translate-y-1 transition-transform" />
                                    </div>
                                </motion.a>
                            ))}
                    </div>

                </div>
            </div>
        </section>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Network, Database, ShieldAlert, GitMerge, FileCode2, Play, RotateCcw } from "lucide-react";

type HexCode = string;

export default function MerkleTreeDemo() {
    const defaultData = ["Row 1", "Row 2", "Row 3", "Row 4"];
    const [data, setData] = useState<string[]>([...defaultData]);
    const [isCorrupted, setIsCorrupted] = useState(false);

    // Simple hash function for visual purposes
    const hashData = (str: string): HexCode => {
        let hash = 0;
        for (let i = 0; i < str.length; i++) hash = (hash << 5) - hash + str.charCodeAt(i);
        return Math.abs(hash).toString(16).padEnd(6, '0').slice(0, 6).toUpperCase();
    };

    // Calculate Tree
    const hash0 = hashData(data[0]);
    const hash1 = hashData(data[1]);
    const hash2 = hashData(data[2]);
    const hash3 = hashData(data[3]);

    const hash01 = hashData(hash0 + hash1);
    const hash23 = hashData(hash2 + hash3);

    const rootHash = hashData(hash01 + hash23);

    const corruptData = () => {
        const newData = [...data];
        newData[2] = "Row 3 (HACKED)";
        setData(newData);
        setIsCorrupted(true);
    };

    const resetData = () => {
        setData([...defaultData]);
        setIsCorrupted(false);
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <GitMerge size={20} className="text-neutral-500" />
                        Merkle Trees (Anti-Entropy)
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        How do databases quickly check if millions of rows are out of sync without comparing raw gigabytes of data over a network? They build a tree of Hashes. If a single row changes at the bottom, the single "Root Hash" at the top changes instantly.
                    </p>

                    <div className="bg-neutral-50 dark:bg-neutral-900/50 p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 mb-6 space-y-3">
                        <div className="flex flex-col gap-1">
                            <span className="text-neutral-500 text-[10px] uppercase font-bold tracking-widest">Root Hash (Top Level)</span>
                            <span className={`text-xl font-bold font-mono transition-colors ${isCorrupted ? 'text-red-500' : 'text-emerald-500'}`}>
                                #{rootHash}
                            </span>
                        </div>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={corruptData}
                        disabled={isCorrupted}
                        className="flex-1 bg-red-500 hover:bg-red-600 text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none disabled:opacity-50 cursor-pointer text-sm"
                    >
                        <ShieldAlert size={16} /> Corrupt Row 3
                    </button>
                    <button
                        onClick={resetData}
                        disabled={!isCorrupted}
                        className="px-6 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-xl font-medium border border-neutral-800 dark:border-neutral-200 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all outline-none cursor-pointer flex items-center justify-center disabled:opacity-50"
                        title="Reset"
                    >
                        <RotateCcw size={16} />
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                <div className="flex-1 flex flex-col items-center justify-between relative py-4 z-10 w-full mb-4">

                    {/* Level 0: Root Hash */}
                    <div className="relative z-20">
                        <motion.div layout className={`px-8 py-4 rounded-xl border-2 flex flex-col items-center justify-center transition-colors shadow-lg ${isCorrupted ? 'border-red-500 bg-red-500/10' : 'border-emerald-500 bg-emerald-500/10'}`}>
                            <span className="text-[10px] uppercase font-bold text-neutral-400 mb-1 tracking-widest">Root Hash</span>
                            <span className={`text-xl font-bold ${isCorrupted ? 'text-red-400' : 'text-emerald-400'}`}>#{rootHash}</span>
                        </motion.div>
                        {/* Down arrows */}
                        <div className="absolute top-full left-1/2 -translate-x-1/2 w-32 h-16 pointer-events-none opacity-50">
                            <svg className="w-full h-full" overflow="visible">
                                <line x1="50%" y1="0" x2="10%" y2="100%" stroke={isCorrupted ? '#ef4444' : '#a3a3a3'} strokeWidth="2" strokeDasharray="4 4" />
                                <line x1="50%" y1="0" x2="90%" y2="100%" stroke={isCorrupted ? '#ef4444' : '#a3a3a3'} strokeWidth="2" strokeDasharray="4 4" />
                            </svg>
                        </div>
                    </div>

                    {/* Level 1: Intermediate Hashes */}
                    <div className="flex w-full justify-around relative z-20 mt-8">
                        <motion.div layout className="px-6 py-3 rounded-xl border border-neutral-700 bg-neutral-800 flex flex-col items-center">
                            <span className="text-[9px] uppercase font-bold text-neutral-500 mb-1">Hash(0+1)</span>
                            <span className="text-neutral-300 font-bold">#{hash01}</span>
                            {/* Down arrows */}
                            <div className="absolute top-full left-1/4 -translate-x-1/2 w-24 h-16 pointer-events-none opacity-50">
                                <svg className="w-full h-full" overflow="visible">
                                    <line x1="50%" y1="0" x2="10%" y2="100%" stroke="#a3a3a3" strokeWidth="2" strokeDasharray="4 4" />
                                    <line x1="50%" y1="0" x2="90%" y2="100%" stroke="#a3a3a3" strokeWidth="2" strokeDasharray="4 4" />
                                </svg>
                            </div>
                        </motion.div>

                        <motion.div layout className={`px-6 py-3 rounded-xl border flex flex-col items-center transition-colors ${isCorrupted ? 'border-red-500/50 bg-red-900/20 shadow-[0_0_15px_rgba(239,68,68,0.2)]' : 'border-neutral-700 bg-neutral-800'}`}>
                            <span className="text-[9px] uppercase font-bold text-neutral-500 mb-1">Hash(2+3)</span>
                            <span className={`font-bold ${isCorrupted ? 'text-red-400' : 'text-neutral-300'}`}>#{hash23}</span>
                            {/* Down arrows */}
                            <div className="absolute top-full right-1/4 translate-x-1/2 w-24 h-16 pointer-events-none opacity-50">
                                <svg className="w-full h-full" overflow="visible">
                                    <line x1="50%" y1="0" x2="10%" y2="100%" stroke={isCorrupted ? '#ef4444' : '#a3a3a3'} strokeWidth="2" strokeDasharray="4 4" />
                                    <line x1="50%" y1="0" x2="90%" y2="100%" stroke="#a3a3a3" strokeWidth="2" strokeDasharray="4 4" />
                                </svg>
                            </div>
                        </motion.div>
                    </div>

                    {/* Level 2: Leaf Hashes */}
                    <div className="flex w-full justify-between px-4 relative z-20 mt-12 gap-2">
                        {[hash0, hash1, hash2, hash3].map((h, i) => {
                            const isHackedLeaf = isCorrupted && i === 2;
                            return (
                                <motion.div layout key={`leaf-${i}`} className={`flex-1 py-2 rounded-lg border flex flex-col items-center justify-center transition-colors ${isHackedLeaf ? 'border-red-500 shadow-[0_0_10px_rgba(239,68,68,0.3)] bg-red-900/10' : 'border-neutral-700 bg-neutral-800/50'}`}>
                                    <span className="text-[8px] uppercase font-bold text-neutral-500 mb-0.5">Hash({i})</span>
                                    <span className={`text-xs font-bold ${isHackedLeaf ? 'text-red-400' : 'text-neutral-400'}`}>#{h}</span>

                                    {/* Down arrow to underlying data */}
                                    <div className="absolute top-full w-full h-8 pointer-events-none opacity-30 flex justify-center">
                                        <svg className="w-2 h-full" overflow="visible">
                                            <line x1="50%" y1="0" x2="50%" y2="100%" stroke={isHackedLeaf ? '#ef4444' : '#a3a3a3'} strokeWidth="2" strokeDasharray="2 2" />
                                        </svg>
                                    </div>
                                </motion.div>
                            )
                        })}
                    </div>

                </div>

                {/* Underling Database Rows */}
                <div className="h-20 bg-black border-t border-neutral-800 p-4 flex gap-2 relative z-20 shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
                    {data.map((row, i) => {
                        const isHackedRow = isCorrupted && i === 2;
                        return (
                            <div key={`data-${i}`} className={`flex-1 h-full rounded border border-dashed flex items-center justify-center p-2 text-center transition-colors ${isHackedRow ? 'border-red-500 bg-red-500/10 text-red-500' : 'border-neutral-700 text-neutral-500'}`}>
                                <span className="text-[10px] font-bold">{row}</span>
                            </div>
                        )
                    })}
                    <div className="absolute -top-3 left-4 bg-neutral-800 px-2 py-0.5 rounded text-[8px] uppercase tracking-widest text-neutral-400 font-bold border border-neutral-700 flex items-center gap-1">
                        <Database size={10} /> Raw DB Blocks
                    </div>
                </div>

            </div>
        </div>
    );
}

