"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Send, Cpu, CheckCircle2, RotateCw, List } from "lucide-react";

interface QueueMessage {
    id: string;
    payload: string;
}

export default function MessageQueueDemo() {
    const [queue, setQueue] = useState<QueueMessage[]>([]);
    const [processedLog, setProcessedLog] = useState<{ id: string, worker: string }[]>([]);

    // Worker States
    const [worker1Active, setWorker1Active] = useState(false);
    const [worker2Active, setWorker2Active] = useState(false);

    // Publisher logic
    const publishMessage = () => {
        const id = crypto.randomUUID();
        const payload = `evt_${Math.floor(Math.random() * 9000) + 1000}`;
        setQueue((prev) => [...prev, { id, payload }]);
    };

    // Worker 1 logic (Faster worker - 1s)
    useEffect(() => {
        if (queue.length === 0 || worker1Active) return;

        setWorker1Active(true);
        setTimeout(() => {
            setQueue((prev) => {
                if (prev.length === 0) return prev;
                const [processed, ...rest] = prev;
                setProcessedLog((logs) => [{ id: processed.id, worker: "Worker A" }, ...logs].slice(0, 10));
                return rest;
            });
            setWorker1Active(false);
        }, 1000);
    }, [queue, worker1Active]);

    // Worker 2 logic (Slower worker - 2.5s)
    useEffect(() => {
        if (queue.length === 0 || worker2Active) return;

        // Slight delay so Worker 1 gets first pick if queue is exactly length 1
        const timeout = setTimeout(() => {
            setQueue((prev) => {
                if (prev.length === 0) return prev;
                const [processed, ...rest] = prev;
                setProcessedLog((logs) => [{ id: processed.id, worker: "Worker B" }, ...logs].slice(0, 10));
                return rest;
            });
            setWorker2Active(false);
        }, 2500);

        setWorker2Active(true);

        return () => clearTimeout(timeout);
    }, [queue, worker2Active]);

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full">
            {/* Publisher & Queue */}
            <div className="bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between">
                <div>
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2">
                            <List size={20} className="text-neutral-500" />
                            Message Broker
                        </h3>
                        <span className="text-xs font-mono bg-neutral-100 dark:bg-neutral-800 px-2 py-1 rounded text-neutral-500">
                            {queue.length} buffered
                        </span>
                    </div>

                    {/* Visual Queue */}
                    <div className="h-[120px] bg-neutral-100 dark:bg-neutral-800/50 border border-neutral-200 dark:border-neutral-700 rounded-xl p-3 flex flex-col justify-end overflow-hidden mb-8 relative">
                        {queue.length === 0 && (
                            <div className="absolute inset-0 flex items-center justify-center text-neutral-400 text-sm">
                                Queue Empty
                            </div>
                        )}
                        <div className="flex gap-2 w-full overflow-hidden flex-nowrap">
                            <AnimatePresence>
                                {queue.map((msg, i) => (
                                    <motion.div
                                        key={msg.id}
                                        initial={{ opacity: 0, x: -20, scale: 0.8 }}
                                        animate={{ opacity: 1, x: 0, scale: 1 }}
                                        exit={{ opacity: 0, scale: 0.8, y: -20 }}
                                        className="h-16 min-w-[3rem] w-12 bg-indigo-500 rounded flex items-center justify-center text-white text-xs font-mono shadow-sm flex-shrink-0"
                                        style={{ zIndex: queue.length - i }}
                                    >
                                        {msg.payload.substring(4, 8)}
                                    </motion.div>
                                ))}
                            </AnimatePresence>
                        </div>
                    </div>
                </div>

                {/* Publish Button */}
                <button
                    onClick={publishMessage}
                    className="w-full bg-neutral-900 dark:bg-white text-white dark:text-black py-4 px-6 rounded-full font-medium transition-all active:scale-95 flex items-center justify-center gap-2 shadow-sm hover:shadow-md cursor-pointer"
                >
                    <Send size={18} />
                    <span>Publish Event</span>
                </button>
            </div>

            {/* Workers & Log */}
            <div className="bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col font-mono relative overflow-hidden h-[350px]">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500/50 to-transparent opacity-50"></div>

                <div className="flex gap-4 mb-6 pb-6 border-b border-neutral-800">
                    {/* Worker A */}
                    <div className={`flex-1 flex flex-col items-center justify-center p-3 rounded-xl border transition-colors ${worker1Active ? 'bg-indigo-900/40 border-indigo-500/50' : 'bg-neutral-800/50 border-neutral-800'}`}>
                        <div className="flex items-center gap-2 text-sm text-neutral-300 mb-2">
                            <Cpu size={14} className={worker1Active ? 'text-indigo-400' : 'text-neutral-500'} />
                            Worker A
                        </div>
                        <div className="h-4 flex items-center">
                            {worker1Active ? <RotateCw size={14} className="text-indigo-400 animate-spin" /> : <span className="text-xs text-neutral-600">Idle (fast)</span>}
                        </div>
                    </div>

                    {/* Worker B */}
                    <div className={`flex-1 flex flex-col items-center justify-center p-3 rounded-xl border transition-colors ${worker2Active ? 'bg-indigo-900/40 border-indigo-500/50' : 'bg-neutral-800/50 border-neutral-800'}`}>
                        <div className="flex items-center gap-2 text-sm text-neutral-300 mb-2">
                            <Cpu size={14} className={worker2Active ? 'text-indigo-400' : 'text-neutral-500'} />
                            Worker B
                        </div>
                        <div className="h-4 flex items-center">
                            {worker2Active ? <RotateCw size={14} className="text-indigo-400 animate-spin" /> : <span className="text-xs text-neutral-600">Idle (slow)</span>}
                        </div>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden relative">
                    <div className="absolute inset-0 overflow-y-auto pr-2 space-y-3 pb-4 scrollbar-thin scrollbar-thumb-neutral-700 scrollbar-track-transparent">
                        <AnimatePresence initial={false}>
                            {processedLog.length === 0 && (
                                <motion.p
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    className="text-neutral-600 text-sm italic text-center mt-4"
                                >
                                    No events processed yet...
                                </motion.p>
                            )}

                            {processedLog.map((log) => (
                                <motion.div
                                    key={log.id}
                                    initial={{ opacity: 0, x: 10 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    className="text-sm flex items-center gap-3 justify-between bg-neutral-800/40 p-2 rounded"
                                >
                                    <div className="flex items-center gap-2 text-green-400">
                                        <CheckCircle2 size={14} />
                                        <span>Processed</span>
                                    </div>
                                    <span className="text-neutral-400 text-xs">{log.worker}</span>
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { motion, useMotionValue, useSpring, useTransform, MotionValue } from "framer-motion";
import { Home, Moon, Sun, Github, Globe, FileText } from "lucide-react";
import { portfolioData } from "@/data/portfolio";

export default function Navbar() {
    const [isDark, setIsDark] = useState(false);
    const { socials } = portfolioData;
    const mouseX = useMotionValue(Infinity);

    useEffect(() => {
        if (window.matchMedia("(prefers-color-scheme: dark)").matches) {
            // eslint-disable-next-line react-hooks/exhaustive-deps
            setIsDark(true);
            document.documentElement.classList.add("dark");
        }
    }, []);

    const toggleTheme = () => {
        setIsDark(!isDark);
        if (!isDark) {
            document.documentElement.classList.add("dark");
        } else {
            document.documentElement.classList.remove("dark");
        }
    };

    return (
        <div
            className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-2"
            onMouseLeave={() => mouseX.set(Infinity)}
            onMouseMove={(e) => mouseX.set(e.clientX)}
        >
            <div className="flex items-end gap-2 px-4 py-3 bg-white/90 dark:bg-neutral-900/90 backdrop-blur-md border border-neutral-200 dark:border-neutral-800 rounded-full shadow-2xl">

                <DockIcon
                    mouseX={mouseX}
                    icon={Home}
                    label="Home"
                    onClick={() => document.getElementById("hero")?.scrollIntoView({ behavior: "smooth" })}
                />

                <div className="w-px h-6 bg-neutral-300 dark:bg-neutral-700 mx-1 self-center" />

                <DockIcon
                    mouseX={mouseX}
                    icon={Github}
                    label="Github"
                    onClick={() => window.open(socials.github, "_blank")}
                />
                <DockIcon
                    mouseX={mouseX}
                    icon={Globe}
                    label="Articles"
                    onClick={() => window.open(socials.medium, "_blank")}
                />
                <DockIcon
                    mouseX={mouseX}
                    icon={XIcon}
                    label="X (Twitter)"
                    onClick={() => window.open(socials.twitter, "_blank")}
                />
                <DockIcon
                    mouseX={mouseX}
                    icon={FileText}
                    label="Resume"
                    onClick={() => window.open(socials.resume, "_blank")}
                />

                <div className="w-px h-6 bg-neutral-700 mx-1 self-center" />

                <button
                    onClick={toggleTheme}
                    className="relative p-3 rounded-full text-neutral-500 hover:text-black dark:text-neutral-400 dark:hover:text-white transition-colors cursor-pointer"
                >
                    {isDark ? <Sun size={20} /> : <Moon size={20} />}
                </button>

            </div>
        </div>
    );
}

function DockIcon({ mouseX, icon: Icon, label, onClick }: { mouseX: MotionValue, icon: React.ElementType, label: string, onClick?: () => void }) {
    const ref = useRef<HTMLButtonElement>(null);

    const distance = useTransform(mouseX, (val) => {
        const bounds = ref.current?.getBoundingClientRect() ?? { x: 0, width: 0 };
        return val - bounds.x - bounds.width / 2;
    });

    // Subtle expansion: 40px base -> 55px max width
    const widthSync = useTransform(distance, [-150, 0, 150], [40, 55, 40]);
    const width = useSpring(widthSync, { mass: 0.1, stiffness: 150, damping: 12 });

    return (
        <motion.button
            ref={ref}
            onClick={onClick}
            style={{ width }}
            className="aspect-square rounded-full flex items-center justify-center relative group cursor-pointer"
        >
            <Icon size={20} className="text-neutral-500 group-hover:text-black dark:text-neutral-400 dark:group-hover:text-white transition-colors" />

            {/* Tooltip */}
            <span className="absolute -top-10 left-1/2 -translate-x-1/2 px-2 py-1 bg-neutral-900 dark:bg-white text-white dark:text-black text-xs font-medium rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none shadow-sm">
                {label}
            </span>
        </motion.button>
    );
}

// Custom X Icon
const XIcon = ({ size, className }: { size?: number, className?: string }) => (
    <svg
        width={size}
        height={size}
        viewBox="0 0 24 24"
        fill="currentColor"
        className={className}
        xmlns="http://www.w3.org/2000/svg"
    >
        <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
    </svg>
);

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Lock, User, Globe, KeyRound, ArrowRight, ShieldCheck, Github, Smartphone, Copy } from "lucide-react";

type Stage = "idle" | "req_auth" | "user_grant" | "auth_code" | "token_exchange" | "api_req" | "done";

export default function OAuthDemo() {
    const [stage, setStage] = useState<Stage>("idle");
    const [logs, setLogs] = useState<{ id: string; msg: string; type: "info" | "success" | "warn" | "error" | "code" }[]>([]);

    const addLog = (msg: string, type: "info" | "success" | "warn" | "error" | "code") => {
        setLogs(prev => [{ id: crypto.randomUUID(), msg, type }, ...prev].slice(0, 7));
    };

    const runFlow = async () => {
        if (stage !== "idle" && stage !== "done") return;

        setStage("idle");
        setLogs([]);
        await new Promise(r => setTimeout(r, 200));

        // 1. Client requests authorization
        setStage("req_auth");
        addLog("Client: Redirecting user to Auth Server (github.com/login/oauth/authorize)...", "info");
        await new Promise(r => setTimeout(r, 1500));

        // 2. User grants permission
        setStage("user_grant");
        addLog("User: Clicks 'Authorize App'.", "success");
        await new Promise(r => setTimeout(r, 1500));

        // 3. Auth Server returns Auth Code
        setStage("auth_code");
        addLog("Auth Server: Redirects back with Authorization Code.", "info");
        addLog("?code=ghO_ab12cd34ef56gh78ij90", "code");
        await new Promise(r => setTimeout(r, 2000));

        // 4. Token Exchange (Backend)
        setStage("token_exchange");
        addLog("Client Backend: Exchanging Code + Client Secret for Access Token...", "warn");
        await new Promise(r => setTimeout(r, 2000));
        addLog("Auth Server: Returned Access Token.", "success");
        addLog("gho_1234567890abcdefghijklmnopqrstuvwxyz", "code");
        await new Promise(r => setTimeout(r, 1000));

        // 5. API Request
        setStage("api_req");
        addLog("Client: Fetching User Profile using Access Token...", "info");
        await new Promise(r => setTimeout(r, 1500));

        // 6. Done
        setStage("done");
        addLog("Resource Server: 200 OK. { name: 'Om Singh', repos: 42 }", "success");
    };

    const isRunning = stage !== "idle" && stage !== "done";

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
