"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Play, RotateCcw, MonitorSmartphone, Server, ArrowDown, ArrowUp, Zap } from "lucide-react";

type Strategy = "polling" | "long_polling" | "sse";
type LogMsg = { id: string, text: string, type: "req" | "res" | "push" };

export default function SseDemo() {
    const [strategy, setStrategy] = useState<Strategy>("sse");
    const [isRunning, setIsRunning] = useState(false);
    const [logs, setLogs] = useState<LogMsg[]>([]);

    const addLog = (text: string, type: "req" | "res" | "push") => {
        setLogs(prev => [{ id: crypto.randomUUID(), text, type }, ...prev].slice(0, 10));
    };

    // Simulation loops
    useEffect(() => {
        if (!isRunning) return;

        let interval: NodeJS.Timeout;
        let eventTarget = new EventTarget();

        // Server Event Generator (Emits every 3-5 seconds randomly)
        const serverLoop = setInterval(() => {
            eventTarget.dispatchEvent(new Event("data_ready"));
        }, 4000);

        if (strategy === "polling") {
            // Standard Polling: Client asks every 1s
            interval = setInterval(() => {
                addLog("Client: Any new data?", "req");
                setTimeout(() => {
                    // 25% chance of actually having data in this short window
                    if (Math.random() < 0.25) {
                        addLog("Server: Yes! Here it is.", "res");
                    } else {
                        addLog("Server: No, try again later.", "res");
                    }
                }, 300);
            }, 1000);

        } else if (strategy === "long_polling") {
            // Long Polling: Client asks, Server holds connection open until data arrives
            const startLongPoll = () => {
                if (!isRunning) return;
                addLog("Client: Any new data? I'll wait.", "req");

                const onData = () => {
                    addLog("Server: Data arrived! Returning response.", "res");
                    eventTarget.removeEventListener("data_ready", onData);
                    // Client immediately reconnects
                    setTimeout(startLongPoll, 300);
                };
                eventTarget.addEventListener("data_ready", onData);
            };
            startLongPoll();

        } else if (strategy === "sse") {
            // Server-Sent Events: One connection, continuous unidirectional stream
            addLog("Client: Opening ONE-WAY data stream.", "req");
            setTimeout(() => {
                addLog("Server: Connection kept ALIVE. Waiting...", "res");
            }, 500);

            const onData = () => {
                addLog("Server -> PUSH DATA: New event!", "push");
            };
            eventTarget.addEventListener("data_ready", onData);
        }

        return () => {
            clearInterval(interval);
            clearInterval(serverLoop);
            setIsRunning(false);
        };
    }, [strategy, isRunning]);

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <Zap size={20} className="text-neutral-500" />
                        SSE vs Polling
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        If a client needs real-time updates (like a stock ticker), how does it get them?
                        <br /><br />
                        <strong>Polling</strong> wastes CPU/Bandwidth. <strong>Long Polling</strong> holds connections open but still requires reconnection. <strong>SSE (Server-Sent Events)</strong> keeps a single persistent HTTP connection open, allowing the server to <em>push</em> data downward anytime.
                    </p>

                    <div className="flex flex-col gap-2 mb-6">
                        {(["polling", "long_polling", "sse"] as Strategy[]).map(s => (
                            <button
                                key={s}
                                onClick={() => { setStrategy(s); setLogs([]); setIsRunning(false); }}
                                className={`px-4 py-2 rounded-xl text-left text-xs font-bold font-mono transition-colors border ${strategy === s
                                        ? 'bg-indigo-500 text-white border-indigo-600'
                                        : 'bg-neutral-100 dark:bg-neutral-800 text-neutral-500 border-neutral-200 dark:border-neutral-700 hover:bg-neutral-200 dark:hover:bg-neutral-700'
                                    }`}
                            >
                                {s === 'polling' ? '1. STANDARD POLLING' : s === 'long_polling' ? '2. LONG POLLING' : '3. SERVER-SENT EVENTS'}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={() => { setLogs([]); setIsRunning(!isRunning); }}
                        className={`flex-1 ${isRunning ? 'bg-red-500 hover:bg-red-600' : 'bg-emerald-500 hover:bg-emerald-600'} text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none cursor-pointer text-sm`}
                    >
                        {isRunning ? <RotateCcw size={16} /> : <Play size={16} />}
                        {isRunning ? 'Stop Simulation' : 'Start Process'}
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                <div className="flex-1 flex flex-col justify-between items-center py-4 relative z-10 w-full mb-8">

                    {/* Client */}
                    <div className="w-16 h-16 rounded-xl border-2 border-indigo-500 bg-indigo-500/10 text-indigo-400 flex flex-col items-center justify-center shadow-[0_0_15px_rgba(99,102,241,0.2)]">
                        <MonitorSmartphone size={32} />
                        <span className="text-[10px] uppercase font-bold mt-1">Client</span>
                    </div>

                    {/* Server */}
                    <div className="w-16 h-16 rounded-xl border-2 border-emerald-500 bg-emerald-500/10 text-emerald-400 flex flex-col items-center justify-center shadow-[0_0_15px_rgba(52,211,153,0.2)] mt-32">
                        <Server size={32} />
                        <span className="text-[10px] uppercase font-bold mt-1">Server</span>
                    </div>

                    {/* Dynamic Network Lines */}
                    <div className="absolute inset-0 pointer-events-none -z-10 flex flex-col items-center justify-center">
                        {/* Main Connection Line */}
                        <div className={`w-1 transition-all duration-300 ${strategy === 'sse' && isRunning ? 'h-32 bg-indigo-500/50 shadow-[0_0_15px_#6366f1]' : 'h-32 border-l-2 border-dashed border-neutral-700'}`} />

                        {/* Animated Request/Responses */}
                        <AnimatePresence>
                            {logs.map((log) => {
                                // Determine animation based on type
                                if (log.type === 'req') {
                                    return (
                                        <motion.div
                                            key={log.id}
                                            initial={{ top: "25%" }} animate={{ top: "65%" }} exit={{ opacity: 0 }} transition={{ duration: strategy === 'long_polling' ? 2 : 0.8 }}
                                            className="absolute text-cyan-400 flex items-center -ml-6"
                                        >
                                            <ArrowDown size={20} />
                                        </motion.div>
                                    )
                                }
                                if (log.type === 'res' || log.type === 'push') {
                                    return (
                                        <motion.div
                                            key={log.id}
                                            initial={{ top: "65%" }} animate={{ top: "25%" }} exit={{ opacity: 0 }} transition={{ duration: 0.8 }}
                                            className={`absolute flex items-center ml-6 ${log.type === 'push' ? 'text-emerald-400' : 'text-purple-400'}`}
                                        >
                                            <ArrowUp size={20} />
                                        </motion.div>
                                    )
                                }
                                return null;
                            })}
                        </AnimatePresence>
                    </div>

                </div>

                {/* Logs */}
                <div className="h-48 bg-black border-t border-neutral-800 p-4 font-mono text-[11px] overflow-y-auto z-30 shrink-0 flex flex-col-reverse shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
                    <AnimatePresence>
                        {logs.map((log) => (
                            <motion.div
                                key={log.id}
                                initial={{ opacity: 0, x: -5 }} animate={{ opacity: 1, x: 0 }}
                                className={`mb-1.5 flex gap-2 ${log.type === 'req' ? 'text-cyan-400' :
                                        log.type === 'res' ? 'text-purple-400' :
                                            log.type === 'push' ? 'text-emerald-400 bg-emerald-900/20 px-1 rounded font-bold' :
                                                'text-neutral-300'
                                    }`}
                            >
                                <span>{log.text}</span>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                    {!isRunning && logs.length === 0 && <span className="text-neutral-600">Select a strategy and click Start.</span>}
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { BarChart, Play, RefreshCcw } from "lucide-react";

interface Span {
    id: string;
    service: string;
    duration: number; // ms
    startTime: number; // relative visually
    color: string;
}

export default function TracingDemo() {
    const [isTracing, setIsTracing] = useState(false);
    const [spans, setSpans] = useState<Span[]>([]);

    // Simulate a random DB bottleneck
    const [dbDelay, setDbDelay] = useState(800);

    const runTrace = () => {
        if (isTracing) return;
        setIsTracing(true);
        setSpans([]);

        // Randomize the bottleneck to make it realistic
        const newDbDelay = Math.floor(Math.random() * 1500) + 300;
        setDbDelay(newDbDelay);

        // Sequence:
        // Gateway (0 - Total Time) -> Auth (50-250) -> Inventory (250-X) -> Payment (X - X+300)

        const S1 = { id: "req_gate", service: "API Gateway", duration: 50 + 200 + newDbDelay + 300, startTime: 0, color: "bg-blue-500 text-blue-100 border-blue-600" };
        const S2 = { id: "req_auth", service: "Authentication", duration: 200, startTime: 50, color: "bg-emerald-500 text-emerald-100 border-emerald-600" };
        const S3 = { id: "req_inv", service: "Inventory DB", duration: newDbDelay, startTime: 250, color: newDbDelay > 1000 ? "bg-red-500 text-red-100 border-red-600" : "bg-purple-500 text-purple-100 border-purple-600" };
        const S4 = { id: "req_pay", service: "Payment Stripe", duration: 300, startTime: 250 + newDbDelay, color: "bg-orange-500 text-orange-100 border-orange-600" };

        let time = 0;
        const totalSimTime = S1.duration;
        const TICK = 50; // evaluate every 50ms

        const interval = setInterval(() => {
            time += TICK;

            setSpans(curr => {
                let next = [...curr];
                if (time >= S1.startTime && !next.find(s => s.id === S1.id)) next.push(S1);
                if (time >= S2.startTime && !next.find(s => s.id === S2.id)) next.push(S2);
                if (time >= S3.startTime && !next.find(s => s.id === S3.id)) next.push(S3);
                if (time >= S4.startTime && !next.find(s => s.id === S4.id)) next.push(S4);
                return next;
            });

            if (time >= totalSimTime) {
                clearInterval(interval);
                setIsTracing(false);
            }
        }, TICK);
    };

    return (
        <div className="w-full bg-[#1e1e1e] border border-neutral-800 shadow-2xl rounded-[2rem] p-8 min-h-[500px] flex flex-col font-sans">

            {/* Header / Controls */}
            <div className="flex justify-between items-center mb-8 border-b border-neutral-800 pb-6">
                <h3 className="text-xl font-medium text-white flex items-center gap-2">
                    <BarChart size={24} className="text-indigo-400" />
                    Datadog Trace Visualizer
                </h3>

                <button
                    onClick={runTrace}
                    disabled={isTracing}
                    className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 border border-indigo-500/50 shadow-md disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer"
                >
                    {isTracing ? <RefreshCcw size={16} className="animate-spin" /> : <Play size={16} />}
                    {isTracing ? "Tracing..." : "Generate New Trace Request"}
                </button>
            </div>

            {/* Trace View */}
            <div className="flex-1 bg-[#111111] border border-neutral-800 rounded-xl overflow-hidden flex flex-col">

                {/* Timeline Axis Header */}
                <div className="flex items-center text-[10px] text-neutral-500 font-mono border-b border-neutral-800 bg-[#151515] p-2 pl-32 relative">
                    <span className="absolute left-4">Service</span>
                    <div className="flex-1 relative h-4">
                        <span className="absolute left-0">0ms</span>
                        <span className="absolute left-1/4">500ms</span>
                        <span className="absolute left-2/4">1000ms</span>
                        <span className="absolute left-3/4">1500ms</span>
                        <span className="absolute right-0">2000ms</span>
                    </div>
                </div>

                {/* Spans Container */}
                <div className="flex-1 p-4 flex flex-col gap-2 relative overflow-hidden bg-[linear-gradient(90deg,transparent_24%,rgba(255,255,255,0.02)_25%,rgba(255,255,255,0.02)_26%,transparent_27%,transparent_74%,rgba(255,255,255,0.02)_75%,rgba(255,255,255,0.02)_76%,transparent_77%,transparent)] bg-[length:400px_100%]">

                    <AnimatePresence>
                        {spans.length === 0 && !isTracing && (
                            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="absolute inset-0 flex items-center justify-center text-neutral-600 font-mono text-sm">
                                Click "Generate New Trace Request" to trace a user Checkout action
                            </motion.div>
                        )}

                        {spans.map(span => {
                            // Map 2000ms max to 100% width
                            const leftPercent = (span.startTime / 2000) * 100;
                            const widthPercent = (span.duration / 2000) * 100;

                            return (
                                <div key={span.id} className="relative flex items-center h-8">
                                    <div className="w-28 shrink-0 text-xs text-neutral-400 font-medium truncate pr-2">
                                        {span.service}
                                    </div>
                                    <div className="flex-1 relative h-full group">
                                        <motion.div
                                            initial={{ width: "0%", opacity: 0 }}
                                            animate={{ width: `${Math.min(widthPercent, 100)}%`, opacity: 1 }}
                                            transition={{ duration: span.duration / 1000, ease: "linear" }}
                                            className={`absolute h-6 rounded border ${span.color} flex items-center justify-end px-2 overflow-hidden hover:brightness-110 cursor-pointer shadow-sm`}
                                            style={{ left: `${leftPercent}%` }}
                                        >
                                            <span className="text-[10px] font-mono whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity drop-shadow-md font-bold">
                                                {span.duration}ms
                                            </span>
                                        </motion.div>
                                    </div>
                                </div>
                            );
                        })}
                    </AnimatePresence>
                </div>

                {/* Insights Panel */}
                <div className="bg-[#151515] p-4 text-xs font-mono border-t border-neutral-800 flex justify-between items-center text-neutral-400">
                    <div className="flex items-center gap-4">
                        <span className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-blue-500"></span> 200 OK</span>
                        <span>Trace ID: {Math.random().toString(36).substring(2, 9)}</span>
                    </div>
                    {dbDelay > 1000 && !isTracing && (
                        <div className="text-red-400 font-bold bg-red-500/10 px-3 py-1 rounded-full border border-red-500/20">
                            🚨 High Latency Detected: database query critically slow resulting in 1.4s overall delay
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Database, Network, ShieldCheck, MailWarning, ThumbsUp, ThumbsDown, ArrowRight, Play, RefreshCcw, Skull } from "lucide-react";

type TxStage = "idle" | "prepare" | "waiting" | "commit" | "abort" | "done";

export default function TwoPhaseCommitDemo() {
    const [stage, setStage] = useState<TxStage>("idle");
    const [votes, setVotes] = useState<Record<number, "yes" | "no" | "waiting">>({
        1: "waiting", 2: "waiting", 3: "waiting"
    });
    const [logs, setLogs] = useState<{ id: string; msg: string; type: "info" | "success" | "warn" | "error" | "action" }[]>([]);

    // Config toggles
    const [shouldFail, setShouldFail] = useState(false);

    const addLog = (msg: string, type: "info" | "success" | "warn" | "error" | "action") => {
        setLogs(prev => [{ id: crypto.randomUUID(), msg, type }, ...prev].slice(0, 6));
    };

    const runTransaction = async () => {
        if (stage !== "idle" && stage !== "done") return;

        setStage("idle");
        setVotes({ 1: "waiting", 2: "waiting", 3: "waiting" });
        setLogs([]);
        await new Promise(r => setTimeout(r, 200));

        // 1. Phase 1: PREPARE
        setStage("prepare");
        addLog("Coordinator: Starting global transaction. Sending PREPARE to all nodes.", "action");
        await new Promise(r => setTimeout(r, 1500));

        // 2. Nodes Vote
        setStage("waiting");

        if (shouldFail) {
            // One node rejects
            setVotes({ 1: "yes", 2: "no", 3: "yes" });
            addLog("Node 1: Voted YES (Locked resources).", "info");
            addLog("Node 3: Voted YES (Locked resources).", "info");
            addLog("Node 2: Voted NO (Constraint violation)! Cannot lock.", "error");
            await new Promise(r => setTimeout(r, 1500));

            // Phase 2: ABORT
            setStage("abort");
            addLog("Coordinator: Received a NO vote. Rolling back entire transaction!", "warn");
            addLog("Coordinator: Sending ABORT to all nodes.", "action");
            await new Promise(r => setTimeout(r, 1500));
            addLog("Nodes: Released all locks and rolled back data.", "info");

        } else {
            // All nodes agree
            setVotes({ 1: "yes", 2: "yes", 3: "yes" });
            addLog("Node 1: Voted YES (Ready to commit).", "info");
            addLog("Node 2: Voted YES (Ready to commit).", "info");
            addLog("Node 3: Voted YES (Ready to commit).", "info");
            await new Promise(r => setTimeout(r, 1500));

            // Phase 2: COMMIT
            setStage("commit");
            addLog("Coordinator: All voted YES! Transaction is safe to finalize.", "success");
            addLog("Coordinator: Sending COMMIT to all nodes.", "action");
            await new Promise(r => setTimeout(r, 1500));
            addLog("Nodes: Finalized writes and released locks. Done.", "success");
        }

        setStage("done");
    };

    const isRunning = stage !== "idle" && stage !== "done";

    return (
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 w-full min-h-[500px]">
            {/* Control Panel */}
            <div className="md:col-span-4 bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between h-full">
                <div>
                    <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2 mb-4">
                        <ShieldCheck size={20} className="text-neutral-500" />
                        Two-Phase Commit (2PC)
                    </h3>

                    <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-6 leading-relaxed">
                        A distributed algorithm that ensures all nodes in a cluster commit a transaction... or none do. It prevents partial writes, ensuring ACID properties across networks.
                        Unlike the Saga Pattern which <i>compensates</i> after failures, 2PC <i>locks</i> everything first.
                    </p>

                    <div className="bg-neutral-50 dark:bg-neutral-900/50 p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 mb-6 space-y-4">

                        <label className="flex items-center gap-3 cursor-pointer group">
                            <div className="relative">
                                <input type="checkbox" className="sr-only" checked={shouldFail} onChange={(e) => setShouldFail(e.target.checked)} disabled={isRunning} />
                                <div className={`block w-10 h-6 rounded-full transition-colors ${shouldFail ? 'bg-red-500' : 'bg-neutral-300 dark:bg-neutral-700'}`}></div>
                                <div className={`absolute left-1 top-1 bg-white w-4 h-4 rounded-full transition-transform ${shouldFail ? 'translate-x-4' : 'translate-x-0'}`}></div>
                            </div>
                            <div className="flex flex-col">
                                <span className={`text-xs font-bold uppercase tracking-wider ${shouldFail ? 'text-red-500' : 'text-neutral-500'}`}>Simulate Constraint Error</span>
                                <span className="text-[9px] text-neutral-500">Node 2 will vote "NO" upon prepare phase.</span>
                            </div>
                        </label>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={runTransaction}
                        disabled={isRunning}
                        className="flex-1 bg-indigo-500 hover:bg-indigo-600 text-white py-4 rounded-xl font-medium flex items-center justify-center gap-2 active:scale-95 transition-all outline-none disabled:opacity-50 cursor-pointer text-sm"
                    >
                        <Play size={16} /> Run Global Transaction
                    </button>
                    <button
                        onClick={() => { setStage("idle"); setVotes({ 1: "waiting", 2: "waiting", 3: "waiting" }); setLogs([]); }}
                        className="px-6 bg-neutral-900 dark:bg-white text-white dark:text-black rounded-xl font-medium border border-neutral-800 dark:border-neutral-200 hover:bg-neutral-800 dark:hover:bg-neutral-200 active:scale-95 transition-all outline-none cursor-pointer flex items-center justify-center"
                        title="Reset"
                    >
                        <RefreshCcw size={16} />
                    </button>
                </div>
            </div>

            {/* Visualization Layer */}
            <div className="md:col-span-8 bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col relative overflow-hidden font-mono min-h-[450px]">

                <div className="flex-1 flex flex-col items-center justify-between relative py-6 px-12 z-10 w-full mb-8">

                    {/* Coordinator Node */}
                    <div className="flex flex-col items-center gap-2 relative z-20">
                        <div className={`w-32 py-4 rounded-2xl flex flex-col items-center justify-center border-2 transition-all duration-300 bg-neutral-900 ${stage === 'prepare' ? 'border-yellow-500 shadow-[0_0_20px_rgba(250,204,21,0.3)]' :
                                stage === 'commit' || (stage === 'done' && !shouldFail) ? 'border-green-500 shadow-[0_0_20px_rgba(34,197,94,0.3)]' :
                                    stage === 'abort' || (stage === 'done' && shouldFail) ? 'border-red-500 shadow-[0_0_20px_rgba(239,68,68,0.3)]' :
                                        'border-indigo-500/50 text-indigo-400'
                            }`}>
                            <div className={`mb-1 ${stage === 'prepare' ? 'text-yellow-400 animate-pulse' : stage === 'commit' ? 'text-green-400' : stage === 'abort' ? 'text-red-400' : 'text-indigo-400'}`}>
                                <Network size={28} />
                            </div>
                            <span className="text-[10px] uppercase font-bold text-white tracking-widest leading-none">Coordinator</span>
                            <span className="text-[8px] text-neutral-500 mt-1">Transaction Manager</span>
                        </div>
                    </div>

                    {/* The 3 Participant Nodes */}
                    <div className="flex w-full justify-between relative mt-20 z-20">
                        {[1, 2, 3].map((id) => {
                            const vote = votes[id as keyof typeof votes];
                            return (
                                <div key={id} className="flex flex-col items-center gap-2 relative">
                                    {/* Vote Status Indicator Float */}
                                    <AnimatePresence>
                                        {stage !== 'idle' && stage !== 'prepare' && (
                                            <motion.div initial={{ y: 0, opacity: 0 }} animate={{ y: -15, opacity: 1 }} className="absolute -top-6 bg-black/50 px-2 py-0.5 rounded border border-neutral-700 backdrop-blur-sm z-30">
                                                {vote === 'yes' ? <ThumbsUp size={12} className="text-green-400" /> :
                                                    vote === 'no' ? <ThumbsDown size={12} className="text-red-400" /> :
                                                        <span className="text-[10px] text-yellow-500 animate-pulse">Waiting...</span>}
                                            </motion.div>
                                        )}
                                    </AnimatePresence>

                                    <div className={`w-20 h-20 rounded-xl border flex flex-col items-center justify-center transition-all bg-neutral-900 ${vote === 'yes' ? 'border-green-500 shadow-[0_0_15px_rgba(34,197,94,0.2)]' :
                                            vote === 'no' ? 'border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.2)] bg-red-900/10' :
                                                'border-neutral-700'
                                        }`}>
                                        <Database size={24} className={vote === 'yes' ? 'text-green-400' : vote === 'no' ? 'text-red-400' : 'text-neutral-500'} />
                                        <span className="text-[9px] uppercase font-bold text-neutral-400 mt-2">Node {id}</span>
                                    </div>
                                </div>
                            )
                        })}
                    </div>

                    {/* Network Layer Animations */}
                    <div className="absolute inset-0 z-10 pointer-events-none">
                        <AnimatePresence>
                            {/* Phase 1: Prepare (Coordinator -> Nodes) */}
                            {stage === 'prepare' && [1, 2, 3].map(i => (
                                <motion.div key={`prep-${i}`} initial={{ top: "25%", left: "50%", opacity: 0 }} animate={{ top: "65%", left: i === 1 ? "15%" : i === 2 ? "50%" : "85%", opacity: 1 }} transition={{ duration: 1.2 }} className="absolute -mt-2 -ml-6 flex items-center gap-1 bg-yellow-500 text-black px-2 py-0.5 rounded shadow-[0_0_10px_#facc15] text-[8px] font-bold">
                                    <MailWarning size={10} /> PREPARE
                                </motion.div>
                            ))}

                            {/* Phase 2a: Commit (Coordinator -> Nodes) */}
                            {stage === 'commit' && [1, 2, 3].map(i => (
                                <motion.div key={`com-${i}`} initial={{ top: "25%", left: "50%", opacity: 0 }} animate={{ top: "65%", left: i === 1 ? "15%" : i === 2 ? "50%" : "85%", opacity: 1 }} transition={{ duration: 1 }} className="absolute -mt-2 -ml-6 flex items-center gap-1 bg-green-500 text-black px-2 py-0.5 rounded shadow-[0_0_10px_#22c55e] text-[8px] font-bold">
                                    <ShieldCheck size={10} /> COMMIT
                                </motion.div>
                            ))}

                            {/* Phase 2b: Abort (Coordinator -> Nodes) */}
                            {stage === 'abort' && [1, 2, 3].map(i => (
                                <motion.div key={`abrt-${i}`} initial={{ top: "25%", left: "50%", opacity: 0 }} animate={{ top: "65%", left: i === 1 ? "15%" : i === 2 ? "50%" : "85%", opacity: 1 }} transition={{ duration: 1 }} className="absolute -mt-2 -ml-6 flex items-center gap-1 bg-red-500 text-white px-2 py-0.5 rounded shadow-[0_0_10px_#ef4444] text-[8px] font-bold">
                                    <Skull size={10} /> ABORT
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>

                    {/* Background Static Connection Lines */}
                    <svg className="absolute inset-0 w-full h-full pointer-events-none -z-10 opacity-30">
                        <line x1="50%" y1="20%" x2="15%" y2="80%" stroke="#4ade80" strokeWidth="2" strokeDasharray="4 4" className={votes[1] === 'yes' ? 'stroke-green-500' : 'stroke-neutral-700'} />
                        <line x1="50%" y1="20%" x2="50%" y2="80%" stroke="#4ade80" strokeWidth="2" strokeDasharray="4 4" className={votes[2] === 'yes' ? 'stroke-green-500' : votes[2] === 'no' ? 'stroke-red-500' : 'stroke-neutral-700'} />
                        <line x1="50%" y1="20%" x2="85%" y2="80%" stroke="#4ade80" strokeWidth="2" strokeDasharray="4 4" className={votes[3] === 'yes' ? 'stroke-green-500' : 'stroke-neutral-700'} />
                    </svg>
                </div>

                {/* Terminal Logs */}
                <div className="h-32 bg-black border-t border-neutral-800 p-4 overflow-y-auto shrink-0 z-20 shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
                    <AnimatePresence>
                        {logs.length === 0 && <span className="text-neutral-600 italic">Waiting...</span>}
                        {logs.map(log => (
                            <motion.div
                                key={log.id}
                                initial={{ opacity: 0, x: -5 }} animate={{ opacity: 1, x: 0 }}
                                className={`text-[11px] mb-1 flex gap-2 ${log.type === 'error' ? 'text-red-400' : log.type === 'success' ? 'text-green-400' : log.type === 'warn' ? 'text-yellow-400' : log.type === 'action' ? 'text-indigo-400 font-bold' : 'text-neutral-300'}`}
                            >
                                <span className="opacity-50 shrink-0"><ArrowRight size={10} className="mt-1" /></span> {log.msg}
                            </motion.div>
                        ))}
                    </AnimatePresence>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Brain, Search, Database, Fingerprint, Crosshair, HelpCircle } from "lucide-react";

// Mock 2D embeddings for visualization
interface VectorItem {
    id: string;
    text: string;
    x: number;
    y: number; // Values 0 to 100 for percentage positioning
    color: string;
}

const KNOWLEDGE_BASE: VectorItem[] = [
    // Animal Cluster
    { id: "1", text: "Dog", x: 20, y: 80, color: "bg-orange-500" },
    { id: "2", text: "Puppy", x: 25, y: 75, color: "bg-orange-400" },
    { id: "3", text: "Cat", x: 30, y: 85, color: "bg-orange-600" },
    { id: "10", text: "Wolf", x: 15, y: 85, color: "bg-orange-700" },
    // Vehicle Cluster
    { id: "4", text: "Car", x: 80, y: 20, color: "bg-blue-500" },
    { id: "5", text: "Truck", x: 85, y: 25, color: "bg-blue-600" },
    { id: "6", text: "Bus", x: 75, y: 15, color: "bg-blue-400" },
    { id: "11", text: "Bicycle", x: 70, y: 25, color: "bg-blue-300" },
    // Food/Fruit Cluster
    { id: "7", text: "Apple", x: 20, y: 20, color: "bg-red-500" },
    { id: "8", text: "Banana", x: 25, y: 15, color: "bg-yellow-500" },
    { id: "9", text: "Orange", x: 15, y: 25, color: "bg-orange-500" },
    { id: "12", text: "Burger", x: 30, y: 25, color: "bg-amber-600" },
    // Technology Cluster
    { id: "13", text: "Computer", x: 80, y: 80, color: "bg-purple-500" },
    { id: "14", text: "Phone", x: 75, y: 85, color: "bg-purple-400" },
    { id: "15", text: "Robot", x: 85, y: 75, color: "bg-purple-600" },
];

// A dictionary of exact mappings and common typos to simulate an embedding model's vocabulary
const DICTIONARY: Record<string, { x: number, y: number }> = {
    // Animals
    "dog": { x: 20, y: 80 }, "pet": { x: 25, y: 80 }, "animal": { x: 25, y: 85 },
    "puppy": { x: 25, y: 75 }, "cat": { x: 30, y: 85 }, "wolf": { x: 15, y: 85 },
    // Vehicles
    "car": { x: 80, y: 20 }, "vehicle": { x: 80, y: 25 }, "vechile": { x: 80, y: 25 }, /* typo */
    "truck": { x: 85, y: 25 }, "bus": { x: 75, y: 15 }, "drive": { x: 75, y: 20 },
    // Foods
    "fruit": { x: 20, y: 20 }, "fruite": { x: 20, y: 20 }, /* typo */ "food": { x: 25, y: 25 },
    "apple": { x: 20, y: 20 }, "banana": { x: 25, y: 15 }, "orange": { x: 15, y: 25 }, "burger": { x: 30, y: 25 },
    // Tech
    "computer": { x: 80, y: 80 }, "tech": { x: 80, y: 85 }, "phone": { x: 75, y: 85 }, "robot": { x: 85, y: 75 }
};

export default function VectorSearchDemo() {
    const [query, setQuery] = useState("");
    const [isSearching, setIsSearching] = useState(false);
    const [queryVector, setQueryVector] = useState<{ x: number, y: number } | null>(null);
    const [results, setResults] = useState<{ item: VectorItem, distance: number }[]>([]);
    const [breakdown, setBreakdown] = useState<{ word: string, x: number, y: number }[]>([]);

    // Simulated embedding model
    const getEmbedding = (text: string) => {
        const words = text.toLowerCase().replace(/[^a-z\s]/g, "").split(/\s+/).filter(w => w.length > 0);
        const vectors: { word: string, x: number, y: number }[] = [];

        words.forEach(w => {
            if (DICTIONARY[w]) {
                vectors.push({ word: w, x: DICTIONARY[w].x, y: DICTIONARY[w].y });
            } else {
                // Determine a pseudo-random coordinate based on the word characters
                let hash = 0;
                for (let i = 0; i < w.length; i++) hash = w.charCodeAt(i) + ((hash << 5) - hash);
                vectors.push({
                    word: w,
                    x: Math.abs((hash % 80) + 10),
                    y: Math.abs(((hash >> 8) % 80) + 10)
                });
            }
        });

        if (vectors.length === 0) return { vector: { x: 50, y: 50 }, components: [] };

        // Average out all word vectors to get the "Sentence Embedding"
        const avgX = vectors.reduce((sum, v) => sum + v.x, 0) / vectors.length;
        const avgY = vectors.reduce((sum, v) => sum + v.y, 0) / vectors.length;

        return { vector: { x: avgX, y: avgY }, components: vectors };
    };

    const calculateDistance = (v1: { x: number, y: number }, v2: { x: number, y: number }) => {
        return Math.sqrt(Math.pow(v1.x - v2.x, 2) + Math.pow(v1.y - v2.y, 2));
    };

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        if (!query.trim() || isSearching) return;

        setIsSearching(true);
        setQueryVector(null);
        setResults([]);
        setBreakdown([]);

        // 1. Convert text to embeddings (Mock)
        setTimeout(() => {
            const { vector, components } = getEmbedding(query);
            setQueryVector(vector);
            setBreakdown(components);

            // 2. Perform KNN Search
            setTimeout(() => {
                const distances = KNOWLEDGE_BASE.map(item => ({
                    item,
                    distance: calculateDistance(vector, { x: item.x, y: item.y })
                })).sort((a, b) => a.distance - b.distance).slice(0, 3); // Get Top 3 K-Nearest Neighbors

                setResults(distances);
                setIsSearching(false);
            }, 800);
        }, 600);
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 w-full min-h-[500px]">
            {/* Input & Results Panel */}
            <div className="bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-6 md:p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between overflow-hidden">
                <div className="flex-1 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-neutral-200 dark:scrollbar-thumb-neutral-800">
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2">
                            <Brain size={20} className="text-neutral-500" />
                            Vector Search
                        </h3>
                    </div>

                    <form onSubmit={handleSearch} className="mb-6">
                        <div className="relative">
                            <input
                                type="text"
                                value={query}
                                onChange={(e) => setQuery(e.target.value)}
                                placeholder="e.g., 'pet vehicle fruit'"
                                className="w-full bg-neutral-100 dark:bg-neutral-950 border border-neutral-200 dark:border-neutral-800 rounded-xl py-4 pl-4 pr-12 outline-none focus:ring-2 focus:ring-purple-500 transition-shadow dark:text-white"
                            />
                            <button
                                type="submit"
                                disabled={isSearching || !query.trim()}
                                className="absolute right-2 top-2 bottom-2 aspect-square bg-purple-500 text-white rounded-lg flex items-center justify-center hover:bg-purple-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors cursor-pointer"
                            >
                                <Search size={18} />
                            </button>
                        </div>
                    </form>

                    {/* Explanation of Average Embedding */}
                    <AnimatePresence>
                        {breakdown.length > 1 && !isSearching && (
                            <motion.div
                                initial={{ opacity: 0, height: 0 }}
                                animate={{ opacity: 1, height: 'auto' }}
                                className="mb-6 p-4 bg-purple-50 dark:bg-purple-900/10 border border-purple-100 dark:border-purple-900/30 rounded-xl"
                            >
                                <h5 className="flex items-center gap-1.5 text-xs font-bold uppercase text-purple-600 dark:text-purple-400 mb-2">
                                    <HelpCircle size={14} /> Multi-Word Averages
                                </h5>
                                <p className="text-xs text-neutral-600 dark:text-neutral-400 mb-3 leading-relaxed">
                                    When you type multiple words, AI averages their coordinates. Your query was grouped like this:
                                </p>
                                <div className="flex flex-wrap gap-2">
                                    {breakdown.map((b, i) => (
                                        <span key={i} className="text-[10px] font-mono bg-white dark:bg-neutral-950 px-2 py-1 rounded border border-neutral-200 dark:border-neutral-800 text-neutral-600 dark:text-neutral-300">
                                            "{b.word}": [{b.x.toFixed(0)}, {b.y.toFixed(0)}]
                                        </span>
                                    ))}
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>

                    <div>
                        <h4 className="text-xs font-bold uppercase tracking-wider text-neutral-500 mb-4 flex items-center gap-2">
                            <Fingerprint size={14} /> Semantic Neighbors (Found)
                        </h4>

                        <div className="space-y-3">
                            {results.length === 0 && !isSearching && (
                                <p className="text-sm text-neutral-400 italic">Enter a query to find semantically similar items, rather than exact keyword matches.</p>
                            )}
                            {isSearching && results.length === 0 && (
                                <div className="p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 bg-neutral-50 dark:bg-neutral-950 flex gap-3 animate-pulse">
                                    <div className="w-8 h-8 rounded-full bg-neutral-200 dark:bg-neutral-800"></div>
                                    <div className="flex-1 space-y-2 py-1">
                                        <div className="h-3 bg-neutral-200 dark:bg-neutral-800 rounded w-1/2"></div>
                                        <div className="h-2 bg-neutral-200 dark:bg-neutral-800 rounded w-1/4"></div>
                                    </div>
                                </div>
                            )}
                            <AnimatePresence>
                                {results.map((result, idx) => (
                                    <motion.div
                                        key={idx}
                                        initial={{ opacity: 0, y: 10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        transition={{ delay: idx * 0.1 }}
                                        className="p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 bg-white dark:bg-neutral-950 flex items-center justify-between"
                                    >
                                        <div className="flex items-center gap-3">
                                            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-bold ${result.item.color}`}>
                                                {idx + 1}
                                            </div>
                                            <span className="font-medium text-neutral-800 dark:text-neutral-200">{result.item.text}</span>
                                        </div>
                                        <div className="text-xs font-mono text-neutral-500">
                                            Dist: {result.distance.toFixed(1)}
                                        </div>
                                    </motion.div>
                                ))}
                            </AnimatePresence>
                        </div>
                    </div>
                </div>
            </div>

            {/* 2D Vector Space Visualization */}
            <div className="bg-neutral-900 border border-neutral-800 rounded-[2rem] p-4 md:p-6 relative flex flex-col min-h-[400px]">
                <div className="flex items-center justify-between mb-4 z-10 shrink-0">
                    <span className="text-neutral-400 text-sm font-mono flex items-center gap-2">
                        <Database size={16} /> 2D Embeddings Map
                    </span>
                </div>

                {/* Grid UI */}
                <div className="flex-1 relative border border-neutral-800 rounded-xl bg-black/50 overflow-hidden">

                    {/* Background Conceptual Clusters */}
                    <div className="absolute w-48 h-48 bg-orange-500/10 rounded-full blur-3xl" style={{ left: '25%', top: '80%', transform: 'translate(-50%, -50%)' }} />
                    <div className="absolute w-48 h-48 bg-blue-500/10 rounded-full blur-3xl" style={{ left: '80%', top: '20%', transform: 'translate(-50%, -50%)' }} />
                    <div className="absolute w-48 h-48 bg-red-500/10 rounded-full blur-3xl" style={{ left: '20%', top: '20%', transform: 'translate(-50%, -50%)' }} />
                    <div className="absolute w-48 h-48 bg-purple-500/10 rounded-full blur-3xl" style={{ left: '80%', top: '80%', transform: 'translate(-50%, -50%)' }} />

                    {/* Semantic Labels */}
                    <span className="absolute left-[25%] top-[65%] -translate-x-1/2 text-[10px] font-bold text-orange-500/30 uppercase tracking-widest pointer-events-none z-0">Animals</span>
                    <span className="absolute left-[80%] top-[40%] -translate-x-1/2 text-[10px] font-bold text-blue-500/30 uppercase tracking-widest pointer-events-none z-0">Vehicles</span>
                    <span className="absolute left-[20%] top-[40%] -translate-x-1/2 text-[10px] font-bold text-red-500/30 uppercase tracking-widest pointer-events-none z-0">Food</span>
                    <span className="absolute left-[80%] top-[65%] -translate-x-1/2 text-[10px] font-bold text-purple-500/30 uppercase tracking-widest pointer-events-none z-0">Tech</span>

                    {/* Grid Lines */}
                    <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-20">
                        {Array.from({ length: 16 }).map((_, i) => (
                            <div key={i} className="border border-neutral-700"></div>
                        ))}
                    </div>

                    {/* Data Points */}
                    {KNOWLEDGE_BASE.map(item => (
                        <div
                            key={item.id}
                            className="absolute transform -translate-x-1/2 -translate-y-1/2 flex flex-col items-center gap-1 group z-10"
                            style={{ left: `${item.x}%`, top: `${item.y}%` }}
                        >
                            <div className={`w-3 h-3 rounded-full ${item.color} shadow-[0_0_10px_currentColor] group-hover:scale-150 transition-transform`} />
                            <span className="text-[10px] font-mono text-neutral-400 bg-neutral-900/80 px-1 rounded opacity-50 group-hover:opacity-100">{item.text}</span>
                        </div>
                    ))}

                    {/* If multiple words, draw lines from the component words to the average center */}
                    <AnimatePresence>
                        {queryVector && breakdown.length > 1 && breakdown.map((b, i) => (
                            <motion.svg
                                key={`line-${i}`}
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 0.5 }}
                                exit={{ opacity: 0 }}
                                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                            >
                                <line
                                    x1={`${b.x}%`} y1={`${b.y}%`}
                                    x2={`${queryVector.x}%`} y2={`${queryVector.y}%`}
                                    stroke="#ec4899" strokeWidth="1" strokeDasharray="4 4"
                                />
                            </motion.svg>
                        ))}
                    </AnimatePresence>

                    {/* Query Point and Search Radius */}
                    <AnimatePresence>
                        {queryVector && (
                            <motion.div
                                initial={{ opacity: 0, scale: 0 }}
                                animate={{ opacity: 1, scale: 1 }}
                                exit={{ opacity: 0, scale: 0 }}
                                className="absolute transform -translate-x-1/2 -translate-y-1/2 z-20 pointer-events-none"
                                style={{ left: `${queryVector.x}%`, top: `${queryVector.y}%` }}
                            >
                                <div className="relative flex items-center justify-center">
                                    <Crosshair size={24} className="text-purple-500 animate-pulse absolute drop-shadow-[0_0_5px_rgba(168,85,247,0.8)]" />

                                    {/* Scan Radius */}
                                    {results.length > 0 && (
                                        <motion.div
                                            initial={{ width: 0, height: 0, opacity: 1 }}
                                            animate={{
                                                width: `${results[results.length - 1].distance * 2.5}%`,
                                                height: `${results[results.length - 1].distance * 2.5}%`,
                                                opacity: 0.15
                                            }}
                                            className="absolute border border-purple-500 bg-purple-500 rounded-full"
                                            style={{ aspectRatio: '1/1' }}
                                        />
                                    )}
                                </div>
                                <span className="absolute top-4 left-4 text-xs font-bold text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)] whitespace-nowrap bg-purple-900/80 border border-purple-500/50 px-2 py-0.5 rounded shadow-lg">
                                    Query: "{query}"
                                </span>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>

                <p className="text-[10px] text-neutral-500 text-center mt-4 shrink-0">
                    Text is converted into numerical coordinates. "Nearest Neighbors" are found using geometry (e.g., Cosine Similarity), not keyword matching. Multi-word queries compute an average coordinate!
                </p>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { Eye } from "lucide-react";

export default function VisitorCounter() {
    const [count, setCount] = useState<number>(0);
    const [loading, setLoading] = useState(true);
    const hasFetched = useRef(false);

    useEffect(() => {
        if (hasFetched.current) return;
        hasFetched.current = true;

        const namespace = "minimal-portfolio-omsingh";
        const key = "visits";
        const localStorageKey = `visited_${namespace}_${key}`;

        const hasVisited = localStorage.getItem(localStorageKey);

        if (!hasVisited) {
            // New visitor: Increment count via proxy
            fetch("/api/visitor?action=up")
                .then((res) => res.json())
                .then((data) => {
                    setCount(data.count);
                    setLoading(false);
                    localStorage.setItem(localStorageKey, "true");
                })
                .catch((err) => {
                    console.error("Error incrementing visitor count:", err);
                    setLoading(false);
                });
        } else {
            // Return visitor: Just get the count (read-only) via proxy
            fetch("/api/visitor")
                .then((res) => res.json())
                .then((data) => {
                    setCount(data.count);
                    setLoading(false);
                })
                .catch((err) => {
                    console.error("Error fetching visitor count:", err);
                    setLoading(false);
                });
        }
    }, []);

    // if (loading) return null; // Commented out to ensure it ALWAYS renders, even if loading/failed
    // We want the user to see the badge, even if it says "..." or "0"


    return (
        <div className="fixed bottom-10 right-10 z-50 flex items-center gap-2 px-3 py-1.5 bg-white/80 dark:bg-neutral-900/80 backdrop-blur-md border border-neutral-200 dark:border-neutral-800 rounded-full shadow-2xl text-xs font-medium text-neutral-600 dark:text-neutral-400 pointer-events-none select-none animate-in fade-in slide-in-from-bottom-4 duration-700">
            <Eye size={14} className="opacity-70" />
            <span>
                Visitor <span className="font-mono font-bold text-black dark:text-white">{count > 0 ? count.toLocaleString() : "..."}</span>
            </span>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Network, Send, User, ServerCog, Plug, Unplug } from "lucide-react";

interface ChatMessage {
    id: string;
    sender: "client" | "server" | "info";
    text: string;
    type: "http" | "ws" | "info";
}

export default function WebSocketDemo() {
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [isConnected, setIsConnected] = useState(false);
    const [inputValue, setInputValue] = useState("");
    const [isConnecting, setIsConnecting] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    // Auto-scroll to bottom
    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const handleConnect = () => {
        setIsConnecting(true);
        // Step 1: Client sends HTTP Upgrade Request
        setMessages(prev => [...prev, { id: crypto.randomUUID(), sender: "client", text: "GET /chat HTTP/1.1\nUpgrade: websocket\nConnection: Upgrade", type: "http" }]);

        // Step 2: Server Responds with 101 Switching Protocols
        setTimeout(() => {
            setMessages(prev => [...prev, { id: crypto.randomUUID(), sender: "server", text: "HTTP/1.1 101 Switching Protocols\nUpgrade: websocket\nConnection: Upgrade", type: "http" }]);

            // Connected!
            setTimeout(() => {
                setIsConnected(true);
                setIsConnecting(false);
                setMessages(prev => [...prev, { id: crypto.randomUUID(), sender: "info", text: "Persistent TCP Connection Established (ws://)", type: "info" }]);
            }, 600);
        }, 800);
    };

    const handleDisconnect = () => {
        setIsConnected(false);
        setMessages(prev => [...prev, { id: crypto.randomUUID(), sender: "info", text: "Connection closed by client.", type: "info" }]);
    };

    const handleSendMessage = (e?: React.FormEvent) => {
        e?.preventDefault();
        if (!inputValue.trim() || !isConnected) return;

        const text = inputValue;
        setInputValue("");

        // Client instantly pushes payload over open pipe
        setMessages(prev => [...prev, { id: crypto.randomUUID(), sender: "client", text, type: "ws" }]);

        // Server instantly pushes back without new handshake
        setTimeout(() => {
            let reply = "Message received loud and clear.";
            if (text.toLowerCase().includes("ping")) reply = "Pong!";
            if (text.toLowerCase().includes("hello")) reply = "Hello! WebSockets make this fast.";

            setMessages(prev => [...prev, { id: crypto.randomUUID(), sender: "server", text: reply, type: "ws" }]);
        }, 400); // Super fast simulated RTT
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full">
            {/* Control Panel / Client View */}
            <div className="bg-white/50 dark:bg-neutral-900/30 backdrop-blur-sm p-8 rounded-[2rem] border border-neutral-200 dark:border-neutral-800 shadow-sm flex flex-col justify-between">
                <div>
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-xl font-medium text-neutral-900 dark:text-white flex items-center gap-2">
                            <User size={20} className="text-neutral-500" />
                            Client App
                        </h3>
                        <div className={`px-3 py-1 text-xs font-bold rounded-full border tracking-wide flex items-center gap-1.5
                            ${isConnected
                                ? "bg-green-500/20 text-green-600 border-green-500/30"
                                : "bg-neutral-500/20 text-neutral-600 border-neutral-500/30"}`}
                        >
                            {isConnected ? <Plug size={12} /> : <Unplug size={12} />}
                            {isConnected ? "CONNECTED" : "OFFLINE"}
                        </div>
                    </div>

                    {/* Connection Controls */}
                    {!isConnected && (
                        <div className="mb-8 flex flex-col items-center justify-center p-6 border border-dashed border-neutral-300 dark:border-neutral-700 rounded-xl bg-neutral-50 dark:bg-neutral-900/50">
                            <Network size={32} className="text-neutral-400 mb-4" />
                            <p className="text-sm text-neutral-600 dark:text-neutral-400 text-center mb-4">
                                WebSockets require an initial HTTP handshake to "Upgrade" the connection protocol.
                            </p>
                            <button
                                onClick={handleConnect}
                                disabled={isConnecting}
                                className="px-6 py-2.5 bg-indigo-500 hover:bg-indigo-600 text-white rounded-lg font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 cursor-pointer"
                            >
                                {isConnecting ? "Negotiating..." : "Initiate Handshake"}
                            </button>
                        </div>
                    )}

                    {isConnected && (
                        <div className="mb-8 flex flex-col items-center justify-center p-6 border border-neutral-200 dark:border-neutral-800 rounded-xl bg-neutral-50 dark:bg-neutral-900/50">
                            <button
                                onClick={handleDisconnect}
                                className="px-6 py-2 rounded-lg border border-red-500/50 text-red-500 hover:bg-red-50 dark:hover:bg-red-950 font-medium transition-colors text-sm cursor-pointer"
                            >
                                Close Connection
                            </button>
                        </div>
                    )}
                </div>

                {/* Chat Input */}
                <form onSubmit={handleSendMessage} className="relative">
                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        placeholder={isConnected ? "Send message via ws://..." : "Connect first to chat"}
                        disabled={!isConnected}
                        className="w-full bg-neutral-100 dark:bg-neutral-950 border border-neutral-200 dark:border-neutral-800 rounded-full py-4 pl-6 pr-14 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/50 disabled:opacity-50 disabled:cursor-not-allowed text-neutral-900 dark:text-neutral-100"
                    />
                    <button
                        type="submit"
                        disabled={!isConnected || !inputValue.trim()}
                        className="absolute right-2 top-2 bottom-2 aspect-square bg-indigo-500 text-white rounded-full flex items-center justify-center hover:bg-indigo-600 disabled:opacity-50 disabled:hover:bg-indigo-500 disabled:cursor-not-allowed transition-colors cursor-pointer"
                    >
                        <Send size={16} className="-ml-0.5" />
                    </button>
                </form>
            </div>

            {/* Server Console / Network Layer */}
            <div className="bg-neutral-900 dark:bg-black p-6 rounded-[2rem] border border-neutral-800 shadow-inner flex flex-col font-mono relative overflow-hidden h-[350px]">
                <div className={`absolute top-0 left-0 w-full h-1 transition-colors duration-1000 ${isConnected ? 'bg-gradient-to-r from-indigo-500/20 via-indigo-500 to-indigo-500/20 shadow-[0_0_15px_rgba(99,102,241,0.5)]' : 'bg-neutral-800'}`}></div>

                <div className="flex items-center justify-between mb-4 pb-4 border-b border-neutral-800">
                    <h3 className="text-neutral-300 text-sm flex items-center gap-2">
                        <ServerCog size={16} className="text-neutral-500" />
                        Network Inspector
                    </h3>
                </div>

                <div className="flex-1 overflow-hidden relative">
                    <div ref={scrollRef} className="absolute inset-0 overflow-y-auto pr-2 space-y-4 pb-4 scrollbar-thin scrollbar-thumb-neutral-700 scrollbar-track-transparent flex flex-col">
                        <AnimatePresence initial={false}>
                            {messages.length === 0 && (
                                <motion.p
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    className="text-neutral-600 text-sm italic m-auto"
                                >
                                    No network activity...
                                </motion.p>
                            )}

                            {messages.map((msg) => (
                                <motion.div
                                    key={msg.id}
                                    initial={{ opacity: 0, y: 10, scale: 0.95 }}
                                    animate={{ opacity: 1, y: 0, scale: 1 }}
                                    className={`flex flex-col max-w-[85%] ${msg.sender === "client" ? "self-end items-end" : msg.sender === "server" ? "self-start items-start" : "self-center my-2"}`}
                                >
                                    {msg.type === "info" ? (
                                        <div className="px-3 py-1 rounded-full bg-neutral-800/50 text-[10px] text-neutral-400 uppercase tracking-widest border border-neutral-700">
                                            {msg.text}
                                        </div>
                                    ) : (
                                        <>
                                            <span className="text-[10px] text-neutral-500 uppercase mb-1 px-1">
                                                {msg.sender === "client" ? "Client ➔ Server" : "Server ➔ Client"}
                                            </span>
                                            <div className={`p-3 rounded-2xl text-xs whitespace-pre-wrap
                                                ${msg.type === "http" ? "bg-neutral-800 text-neutral-300 border border-neutral-700" : ""}
                                                ${msg.type === "ws" && msg.sender === "client" ? "bg-indigo-600 text-white rounded-tr-sm" : ""}
                                                ${msg.type === "ws" && msg.sender === "server" ? "bg-neutral-800 border border-indigo-500/30 text-indigo-100 rounded-tl-sm" : ""}
                                            `}>
                                                {msg.text}
                                            </div>
                                        </>
                                    )}
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>
                </div>
            </div>
        </div>
    );
}
